(function (global) {
  "use strict";

  function normalizeKey(value) {
    return String(value || "")
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9_-]/g, "_")
      .replace(/_+/g, "_")
      .replace(/^_|_$/g, "");
  }

  function create(input = {}) {
    const runtime = global.INFINICUS.DT.runtime;

    if (!input.legalName || !input.businessKey) {
      return runtime.failure(
        "BUSINESS_IDENTITY_INVALID",
        "legalName and businessKey are required."
      );
    }

    const businessKey = normalizeKey(input.businessKey);

    if (!businessKey) {
      return runtime.failure(
        "BUSINESS_KEY_INVALID",
        "businessKey could not be normalized."
      );
    }

    return runtime.success({
      businessId:
        input.businessId ||
        runtime.createId("dt_business"),
      businessKey,
      legalName:
        String(input.legalName),
      tradingName:
        String(input.tradingName || input.legalName),
      registrationNumber:
        input.registrationNumber || null,
      countryCode:
        String(input.countryCode || ""),
      industry:
        String(input.industry || ""),
      ownerId:
        String(input.ownerId || ""),
      tenantId:
        String(input.tenantId || ""),
      metadata:
        runtime.clone(input.metadata || {}),
      status:
        String(input.status || "active"),
      createdAt:
        new Date().toISOString(),
      updatedAt:
        new Date().toISOString()
    });
  }

  global.INFINICUS.DT.businessIdentityModel =
    Object.freeze({
      normalizeKey,
      create
    });
})(window);

/* --- INFINICUS-DT-02-Business-Identity-Twin-Instance-Registry/src/model/twin-instance.js --- */
(function (global) {
  "use strict";

  const TWIN_TYPES = Object.freeze([
    "business",
    "branch",
    "department",
    "project",
    "business_unit",
    "location",
    "subsidiary"
  ]);

  function create(input = {}) {
    const runtime = global.INFINICUS.DT.runtime;
    const twinType = String(input.twinType || "business");

    if (
      !input.businessId ||
      !input.name ||
      !TWIN_TYPES.includes(twinType)
    ) {
      return runtime.failure(
        "TWIN_INSTANCE_INVALID",
        "businessId, name, and a supported twinType are required."
      );
    }

    if (
      twinType !== "business" &&
      !input.parentTwinId
    ) {
      return runtime.failure(
        "PARENT_TWIN_REQUIRED",
        "Non-business twin instances require a parentTwinId."
      );
    }

    return runtime.success({
      twinId:
        input.twinId ||
        runtime.createId("dt_twin"),
      businessId:
        String(input.businessId),
      twinKey:
        global.INFINICUS.DT.businessIdentityModel
          .normalizeKey(
            input.twinKey ||
            `${input.businessId}_${input.name}`
          ),
      name:
        String(input.name),
      twinType,
      parentTwinId:
        input.parentTwinId || null,
      aliases:
        Array.isArray(input.aliases)
          ? [...new Set(input.aliases.map(String))]
          : [],
      ownerId:
        String(input.ownerId || ""),
      tenantId:
        String(input.tenantId || ""),
      lifecycleState:
        String(input.lifecycleState || "initializing"),
      lifecycleHistory: [{
        from: null,
        to:
          String(input.lifecycleState || "initializing"),
        reason:
          "Twin instance created.",
        changedAt:
          new Date().toISOString()
      }],
      metadata:
        runtime.clone(input.metadata || {}),
      createdAt:
        new Date().toISOString(),
      updatedAt:
        new Date().toISOString()
    });
  }

  global.INFINICUS.DT.twinInstanceModel =
    Object.freeze({
      TWIN_TYPES,
      create
    });
})(window);

/* --- INFINICUS-DT-02-Business-Identity-Twin-Instance-Registry/src/validation/hierarchy-validator.js --- */
(function (global) {
  "use strict";

  function validate(parent, child) {
    if (!parent) {
      return {
        valid: child.twinType === "business",
        issues:
          child.twinType === "business"
            ? []
            : ["Parent twin is required."]
      };
    }

    const issues = [];

    if (parent.businessId !== child.businessId) {
      issues.push(
        "Parent and child twins must belong to the same business identity."
      );
    }

    if (parent.lifecycleState === "retired") {
      issues.push(
        "A retired twin cannot receive new child twins."
      );
    }

    if (parent.twinId === child.twinId) {
      issues.push(
        "A twin cannot be its own parent."
      );
    }

    return {
      valid: issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.twinHierarchyValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-02-Business-Identity-Twin-Instance-Registry/src/storage/twin-registry-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_TWIN_REGISTRY";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        if (!db.objectStoreNames.contains("businesses")) {
          const store =
            db.createObjectStore(
              "businesses",
              { keyPath: "businessId" }
            );

          store.createIndex(
            "businessKey",
            "businessKey",
            { unique: true }
          );
        }

        if (!db.objectStoreNames.contains("twins")) {
          const store =
            db.createObjectStore(
              "twins",
              { keyPath: "twinId" }
            );

          store.createIndex(
            "twinKey",
            "twinKey",
            { unique: true }
          );

          store.createIndex(
            "businessId",
            "businessId",
            { unique: false }
          );

          store.createIndex(
            "parentTwinId",
            "parentTwinId",
            { unique: false }
          );
        }

        if (!db.objectStoreNames.contains("schema_handoffs")) {
          db.createObjectStore(
            "schema_handoffs",
            { keyPath: "schemaHandoffId" }
          );
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");

      await request(
        tx.objectStore(storeName).put(structuredClone(record))
      );

      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "TWIN_REGISTRY_STORAGE_ERROR",
        error?.message || "Twin registry storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");

      const value = await request(
        tx.objectStore(storeName).get(id)
      );

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "TWIN_REGISTRY_RECORD_NOT_FOUND",
            "Twin registry record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "TWIN_REGISTRY_STORAGE_ERROR",
        error?.message || "Twin registry retrieval failed."
      );
    }
  }

  async function getByIndex(storeName, indexName, value) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");

      const record = await request(
        tx.objectStore(storeName)
          .index(indexName)
          .get(value)
      );

      return record
        ? runtime.success(structuredClone(record))
        : runtime.failure(
            "TWIN_REGISTRY_RECORD_NOT_FOUND",
            "Twin registry record was not found.",
            {
              storeName,
              indexName,
              value
            }
          );
    } catch (error) {
      return runtime.failure(
        "TWIN_REGISTRY_STORAGE_ERROR",
        error?.message || "Twin registry indexed retrieval failed."
      );
    }
  }

  async function listByIndex(storeName, indexName, value) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");

      const records = await request(
        tx.objectStore(storeName)
          .index(indexName)
          .getAll(value)
      );

      return runtime.success(
        records.map(structuredClone)
      );
    } catch (error) {
      return runtime.failure(
        "TWIN_REGISTRY_STORAGE_ERROR",
        error?.message || "Twin registry indexed listing failed."
      );
    }
  }

  async function list(storeName) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");

      const records = await request(
        tx.objectStore(storeName).getAll()
      );

      return runtime.success(
        records.map(structuredClone)
      );
    } catch (error) {
      return runtime.failure(
        "TWIN_REGISTRY_STORAGE_ERROR",
        error?.message || "Twin registry listing failed."
      );
    }
  }

  global.INFINICUS.DT.twinRegistryStore =
    Object.freeze({
      open,
      put,
      get,
      getByIndex,
      listByIndex,
      list
    });
})(window);

/* --- INFINICUS-DT-02-Business-Identity-Twin-Instance-Registry/src/engine/twin-instance-registry.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function registerBusiness(input = {}) {
    const built =
      global.INFINICUS.DT
        .businessIdentityModel
        .create(input);

    if (!built.ok) return built;

    const existing =
      await global.INFINICUS.DT
        .twinRegistryStore
        .getByIndex(
          "businesses",
          "businessKey",
          built.data.businessKey
        );

    if (existing.ok) {
      return runtime.failure(
        "BUSINESS_KEY_DUPLICATE",
        `Business key already exists: ${built.data.businessKey}`
      );
    }

    const stored =
      await global.INFINICUS.DT
        .twinRegistryStore
        .put("businesses", built.data);

    if (stored.ok) {
      await runtime.emit(
        "dt.business_identity.registered",
        stored.data
      );
    }

    return stored;
  }

  async function createTwin(input = {}) {
    const business =
      await global.INFINICUS.DT
        .twinRegistryStore
        .get("businesses", input.businessId);

    if (!business.ok) return business;

    const built =
      global.INFINICUS.DT
        .twinInstanceModel
        .create({
          ...input,
          ownerId:
            input.ownerId || business.data.ownerId,
          tenantId:
            input.tenantId || business.data.tenantId
        });

    if (!built.ok) return built;

    let parent = null;

    if (built.data.parentTwinId) {
      const found =
        await global.INFINICUS.DT
          .twinRegistryStore
          .get(
            "twins",
            built.data.parentTwinId
          );

      if (!found.ok) return found;
      parent = found.data;
    }

    const hierarchy =
      global.INFINICUS.DT
        .twinHierarchyValidator
        .validate(parent, built.data);

    if (!hierarchy.valid) {
      return runtime.failure(
        "TWIN_HIERARCHY_INVALID",
        "Twin hierarchy validation failed.",
        hierarchy
      );
    }

    const duplicate =
      await global.INFINICUS.DT
        .twinRegistryStore
        .getByIndex(
          "twins",
          "twinKey",
          built.data.twinKey
        );

    if (duplicate.ok) {
      return runtime.failure(
        "TWIN_KEY_DUPLICATE",
        `Twin key already exists: ${built.data.twinKey}`
      );
    }

    const stored =
      await global.INFINICUS.DT
        .twinRegistryStore
        .put("twins", built.data);

    if (!stored.ok) return stored;

    runtime.registerTwin(
      built.data.twinId,
      built.data,
      {
        businessId:
          built.data.businessId,
        twinType:
          built.data.twinType
      }
    );

    await runtime.emit(
      "dt.twin_instance.created",
      stored.data
    );

    return stored;
  }

  async function transitionTwin({
    twinId,
    to,
    reason = ""
  } = {}) {
    const found =
      await global.INFINICUS.DT
        .twinRegistryStore
        .get("twins", twinId);

    if (!found.ok) return found;

    const from =
      found.data.lifecycleState;

    if (!runtime.lifecycle.mayTransition(from, to)) {
      return runtime.failure(
        "TWIN_LIFECYCLE_TRANSITION_INVALID",
        `Twin cannot transition from ${from} to ${to}.`
      );
    }

    const updated = {
      ...found.data,
      lifecycleState:
        String(to),
      lifecycleHistory: [
        ...found.data.lifecycleHistory,
        {
          from,
          to:
            String(to),
          reason:
            String(reason || ""),
          changedAt:
            new Date().toISOString()
        }
      ],
      updatedAt:
        new Date().toISOString()
    };

    const stored =
      await global.INFINICUS.DT
        .twinRegistryStore
        .put("twins", updated);

    if (stored.ok) {
      await runtime.emit(
        "dt.twin_instance.transitioned",
        {
          twinId,
          from,
          to,
          reason
        }
      );
    }

    return stored;
  }

  async function prepareSchemaHandoff({
    twinId
  } = {}) {
    const twin =
      await global.INFINICUS.DT
        .twinRegistryStore
        .get("twins", twinId);

    if (!twin.ok) return twin;

    const business =
      await global.INFINICUS.DT
        .twinRegistryStore
        .get(
          "businesses",
          twin.data.businessId
        );

    if (!business.ok) return business;

    const children =
      await global.INFINICUS.DT
        .twinRegistryStore
        .listByIndex(
          "twins",
          "parentTwinId",
          twinId
        );

    if (!children.ok) return children;

    const handoff = {
      schemaHandoffId:
        runtime.createId("dt_schema_handoff"),
      targetBlock: "DT-03",
      business:
        runtime.clone(business.data),
      twin:
        runtime.clone(twin.data),
      childTwins:
        children.data.map(runtime.clone),
      requestedSchemaVersion:
        "1.0.0",
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    const stored =
      await global.INFINICUS.DT
        .twinRegistryStore
        .put("schema_handoffs", handoff);

    if (stored.ok) {
      await runtime.emit(
        "dt.schema_handoff.prepared",
        stored.data
      );
    }

    return stored;
  }

  const api = Object.freeze({
    registerBusiness,
    createTwin,
    transitionTwin,
    prepareSchemaHandoff,
    getBusiness: ({ businessId }) =>
      global.INFINICUS.DT
        .twinRegistryStore
        .get("businesses", businessId),
    getBusinessByKey: ({ businessKey }) =>
      global.INFINICUS.DT
        .twinRegistryStore
        .getByIndex(
          "businesses",
          "businessKey",
          global.INFINICUS.DT
            .businessIdentityModel
            .normalizeKey(businessKey)
        ),
    getTwin: ({ twinId }) =>
      global.INFINICUS.DT
        .twinRegistryStore
        .get("twins", twinId),
    getTwinByKey: ({ twinKey }) =>
      global.INFINICUS.DT
        .twinRegistryStore
        .getByIndex(
          "twins",
          "twinKey",
          global.INFINICUS.DT
            .businessIdentityModel
            .normalizeKey(twinKey)
        ),
    listBusinessTwins: ({ businessId }) =>
      global.INFINICUS.DT
        .twinRegistryStore
        .listByIndex(
          "twins",
          "businessId",
          businessId
        ),
    getSchemaHandoff: ({ schemaHandoffId }) =>
      global.INFINICUS.DT
        .twinRegistryStore
        .get(
          "schema_handoffs",
          schemaHandoffId
        )
  });

  runtime.registerService(
    "dt.twin_instance_registry",
    api,
    { block: "DT-02" }
  );

  runtime.registerRoute(
    "dt.business_identity.register",
    registerBusiness
  );

  runtime.registerRoute(
    "dt.twin_instance.create",
    createTwin
  );

  runtime.registerRoute(
    "dt.twin_instance.transition",
    transitionTwin
  );

  runtime.registerRoute(
    "dt.schema_handoff.prepare",
    prepareSchemaHandoff
  );

  global.INFINICUS.DT.twinInstanceRegistry = api;
})(window);

