/* --- INFINICUS-DT-03-Twin-Schema-Business-Ontology-Engine/src/validation/ontology-validator.js --- */
(function (global) {
  "use strict";

  function validate(ontology) {
    const issues = [];
    const entityIds =
      new Set(ontology.entityTypes.map(item => item.entityTypeId));

    const entityCodes =
      new Set();

    for (const entity of ontology.entityTypes) {
      if (entityCodes.has(entity.code)) {
        issues.push(`Duplicate entity type code: ${entity.code}`);
      }

      entityCodes.add(entity.code);

      const attributeCodes = new Set();

      for (const attribute of entity.attributes || []) {
        if (attributeCodes.has(attribute.code)) {
          issues.push(
            `Duplicate attribute code ${attribute.code} in ${entity.code}`
          );
        }

        attributeCodes.add(attribute.code);
      }

      if (
        entity.parentEntityTypeId &&
        !entityIds.has(entity.parentEntityTypeId)
      ) {
        issues.push(
          `Unknown parent entity type: ${entity.parentEntityTypeId}`
        );
      }
    }

    for (const relationship of ontology.relationshipTypes) {
      if (!entityIds.has(relationship.sourceEntityTypeId)) {
        issues.push(
          `Unknown relationship source: ${relationship.sourceEntityTypeId}`
        );
      }

      if (!entityIds.has(relationship.targetEntityTypeId)) {
        issues.push(
          `Unknown relationship target: ${relationship.targetEntityTypeId}`
        );
      }
    }

    return {
      valid: issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.ontologyValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-03-Twin-Schema-Business-Ontology-Engine/src/validation/compatibility-checker.js --- */
(function (global) {
  "use strict";

  function check(previous, next) {
    if (!previous) {
      return {
        compatible: true,
        breakingChanges: []
      };
    }

    const breakingChanges = [];
    const nextByCode =
      new Map(next.entityTypes.map(item => [item.code, item]));

    for (const priorEntity of previous.entityTypes) {
      const nextEntity = nextByCode.get(priorEntity.code);

      if (!nextEntity) {
        breakingChanges.push(
          `Entity type removed: ${priorEntity.code}`
        );
        continue;
      }

      const nextAttributes =
        new Map(
          (nextEntity.attributes || [])
            .map(item => [item.code, item])
        );

      for (const priorAttribute of priorEntity.attributes || []) {
        const nextAttribute =
          nextAttributes.get(priorAttribute.code);

        if (!nextAttribute) {
          breakingChanges.push(
            `Attribute removed: ${priorEntity.code}.${priorAttribute.code}`
          );
        } else if (
          nextAttribute.valueType !==
          priorAttribute.valueType
        ) {
          breakingChanges.push(
            `Attribute type changed: ${priorEntity.code}.${priorAttribute.code}`
          );
        }
      }
    }

    return {
      compatible:
        breakingChanges.length === 0,
      breakingChanges
    };
  }

  global.INFINICUS.DT.ontologyCompatibilityChecker =
    Object.freeze({ check });
})(window);

/* --- INFINICUS-DT-03-Twin-Schema-Business-Ontology-Engine/src/storage/ontology-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_ONTOLOGY";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        for (const [name, keyPath] of [
          ["ontologies", "ontologyId"],
          ["intake_handoffs", "intakeHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            const store =
              db.createObjectStore(name, { keyPath });

            if (name === "ontologies") {
              store.createIndex(
                "twinId",
                "twinId",
                { unique: false }
              );
            }
          }
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(
        tx.objectStore(storeName).put(structuredClone(record))
      );
      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "ONTOLOGY_STORAGE_ERROR",
        error?.message || "Ontology storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(
        tx.objectStore(storeName).get(id)
      );

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "ONTOLOGY_RECORD_NOT_FOUND",
            "Ontology record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "ONTOLOGY_STORAGE_ERROR",
        error?.message || "Ontology retrieval failed."
      );
    }
  }

  async function listByTwin(twinId) {
    try {
      const db = await open();
      const tx = db.transaction("ontologies", "readonly");
      const values = await request(
        tx.objectStore("ontologies")
          .index("twinId")
          .getAll(twinId)
      );

      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure(
        "ONTOLOGY_STORAGE_ERROR",
        error?.message || "Ontology listing failed."
      );
    }
  }

  global.INFINICUS.DT.ontologyStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-03-Twin-Schema-Business-Ontology-Engine/src/engine/schema-ontology-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function registerOntology(input = {}) {
    const twin =
      await global.INFINICUS.DT
        .twinInstanceRegistry
        .getTwin({
          twinId: input.twinId
        });

    if (!twin.ok) return twin;

    const entityTypes = [];

    for (const inputEntity of input.entityTypes || []) {
      const built =
        global.INFINICUS.DT
          .entityTypeModel
          .create(inputEntity);

      if (!built.ok) return built;
      entityTypes.push(built.data);
    }

    const relationshipTypes = [];

    for (const inputRelationship of input.relationshipTypes || []) {
      const built =
        global.INFINICUS.DT
          .relationshipTypeModel
          .create(inputRelationship);

      if (!built.ok) return built;
      relationshipTypes.push(built.data);
    }

    const stateModels = [];

    for (const inputStateModel of input.stateModels || []) {
      const built =
        global.INFINICUS.DT
          .stateModel
          .create(inputStateModel);

      if (!built.ok) return built;
      stateModels.push(built.data);
    }

    const built =
      global.INFINICUS.DT
        .ontologyDefinitionModel
        .create({
          ...input,
          entityTypes,
          relationshipTypes,
          stateModels
        });

    if (!built.ok) return built;

    const validation =
      global.INFINICUS.DT
        .ontologyValidator
        .validate(built.data);

    if (!validation.valid) {
      return runtime.failure(
        "ONTOLOGY_VALIDATION_FAILED",
        "Ontology validation failed.",
        validation
      );
    }

    let previous = null;

    if (built.data.supersedesOntologyId) {
      const found =
        await global.INFINICUS.DT
          .ontologyStore
          .get(
            "ontologies",
            built.data.supersedesOntologyId
          );

      if (!found.ok) return found;
      previous = found.data;

      const compatibility =
        global.INFINICUS.DT
          .ontologyCompatibilityChecker
          .check(previous, built.data);

      if (
        !compatibility.compatible &&
        input.allowBreakingChanges !== true
      ) {
        return runtime.failure(
          "ONTOLOGY_BREAKING_CHANGE",
          "Breaking ontology changes require explicit approval.",
          compatibility
        );
      }
    }

    const stored =
      await global.INFINICUS.DT
        .ontologyStore
        .put("ontologies", built.data);

    if (!stored.ok) return stored;

    runtime.registerSchema(
      built.data.ontologyId,
      built.data,
      {
        twinId:
          built.data.twinId,
        version:
          built.data.version
      }
    );

    await runtime.emit(
      "dt.ontology.registered",
      stored.data
    );

    return runtime.success({
      ontology:
        stored.data,
      supersededOntology:
        previous
    });
  }

  async function prepareIntakeHandoff({
    ontologyId,
    schemaHandoffId
  } = {}) {
    const ontology =
      await global.INFINICUS.DT
        .ontologyStore
        .get("ontologies", ontologyId);

    if (!ontology.ok) return ontology;

    const identity =
      await global.INFINICUS.DT
        .twinInstanceRegistry
        .getSchemaHandoff({
          schemaHandoffId
        });

    if (!identity.ok) return identity;

    if (
      identity.data.twin.twinId !==
      ontology.data.twinId
    ) {
      return runtime.failure(
        "ONTOLOGY_TWIN_MISMATCH",
        "Ontology and identity handoff reference different twins."
      );
    }

    const handoff = {
      intakeHandoffId:
        runtime.createId("dt_intake_handoff"),
      targetBlock: "DT-04",
      schemaHandoffId,
      ontologyId,
      twin:
        runtime.clone(identity.data.twin),
      business:
        runtime.clone(identity.data.business),
      ontology:
        runtime.clone(ontology.data),
      requiredEntityTypes:
        ontology.data.entityTypes.map(entity => ({
          entityTypeId:
            entity.entityTypeId,
          code:
            entity.code,
          attributes:
            entity.attributes
              .filter(attribute => attribute.required)
              .map(attribute => attribute.code)
        })),
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    const stored =
      await global.INFINICUS.DT
        .ontologyStore
        .put("intake_handoffs", handoff);

    if (stored.ok) {
      await runtime.emit(
        "dt.intake_handoff.prepared",
        stored.data
      );
    }

    return stored;
  }

  const api = Object.freeze({
    registerOntology,
    prepareIntakeHandoff,
    getOntology: ({ ontologyId }) =>
      global.INFINICUS.DT
        .ontologyStore
        .get("ontologies", ontologyId),
    listTwinOntologies: ({ twinId }) =>
      global.INFINICUS.DT
        .ontologyStore
        .listByTwin(twinId),
    getIntakeHandoff: ({ intakeHandoffId }) =>
      global.INFINICUS.DT
        .ontologyStore
        .get("intake_handoffs", intakeHandoffId)
  });

  runtime.registerService(
    "dt.schema_ontology",
    api,
    { block: "DT-03" }
  );

  runtime.registerRoute(
    "dt.ontology.register",
    registerOntology
  );

  runtime.registerRoute(
    "dt.intake_handoff.prepare",
    prepareIntakeHandoff
  );

  global.INFINICUS.DT.schemaOntologyEngine = api;
})(window);

