/* --- INFINICUS-DT-05-Business-Entity-Relationship-Graph-Engine/src/validation/entity-validator.js --- */
(function (global) {
  "use strict";

  function validate(entity, entityType) {
    const issues = [];

    if (!entityType) {
      issues.push("Entity type was not found in the ontology.");
      return { valid: false, issues };
    }

    const allowed =
      new Map(
        (entityType.attributes || [])
          .map(attribute => [attribute.code, attribute])
      );

    for (const attribute of entityType.attributes || []) {
      if (
        attribute.required &&
        (
          entity.attributes[attribute.code] == null ||
          entity.attributes[attribute.code] === ""
        )
      ) {
        issues.push(
          `Required attribute is missing: ${attribute.code}`
        );
      }
    }

    for (const key of Object.keys(entity.attributes || {})) {
      if (!allowed.has(key)) {
        issues.push(
          `Attribute is not defined by the ontology: ${key}`
        );
      }
    }

    return {
      valid: issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.entityInstanceValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-05-Business-Entity-Relationship-Graph-Engine/src/validation/relationship-validator.js --- */
(function (global) {
  "use strict";

  function validate({
    relationship,
    relationshipType,
    sourceEntity,
    targetEntity,
    existingRelationships = []
  }) {
    const issues = [];

    if (!relationshipType) {
      issues.push("Relationship type was not found in the ontology.");
      return { valid: false, issues };
    }

    if (!sourceEntity) {
      issues.push("Source entity instance was not found.");
    }

    if (!targetEntity) {
      issues.push("Target entity instance was not found.");
    }

    if (
      sourceEntity &&
      sourceEntity.entityTypeId !==
      relationshipType.sourceEntityTypeId
    ) {
      issues.push("Source entity type does not match relationship definition.");
    }

    if (
      targetEntity &&
      targetEntity.entityTypeId !==
      relationshipType.targetEntityTypeId
    ) {
      issues.push("Target entity type does not match relationship definition.");
    }

    const sameType =
      existingRelationships.filter(item =>
        item.relationshipTypeId ===
        relationship.relationshipTypeId
      );

    if (
      relationshipType.cardinality === "one_to_one" &&
      sameType.some(item =>
        item.sourceEntityInstanceId ===
          relationship.sourceEntityInstanceId ||
        item.targetEntityInstanceId ===
          relationship.targetEntityInstanceId
      )
    ) {
      issues.push("One-to-one cardinality would be violated.");
    }

    if (
      relationshipType.cardinality === "one_to_many" &&
      sameType.some(item =>
        item.targetEntityInstanceId ===
        relationship.targetEntityInstanceId
      )
    ) {
      issues.push("One-to-many target cardinality would be violated.");
    }

    if (
      relationshipType.cardinality === "many_to_one" &&
      sameType.some(item =>
        item.sourceEntityInstanceId ===
        relationship.sourceEntityInstanceId
      )
    ) {
      issues.push("Many-to-one source cardinality would be violated.");
    }

    return {
      valid: issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.relationshipInstanceValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-05-Business-Entity-Relationship-Graph-Engine/src/graph/graph-index.js --- */
(function (global) {
  "use strict";

  function build(entities = [], relationships = []) {
    const adjacency = new Map();

    for (const entity of entities) {
      adjacency.set(entity.entityInstanceId, []);
    }

    for (const relationship of relationships) {
      if (!adjacency.has(relationship.sourceEntityInstanceId)) {
        adjacency.set(relationship.sourceEntityInstanceId, []);
      }

      adjacency.get(relationship.sourceEntityInstanceId).push({
        relationshipInstanceId:
          relationship.relationshipInstanceId,
        relationshipTypeId:
          relationship.relationshipTypeId,
        direction: "outbound",
        entityInstanceId:
          relationship.targetEntityInstanceId
      });

      if (!adjacency.has(relationship.targetEntityInstanceId)) {
        adjacency.set(relationship.targetEntityInstanceId, []);
      }

      adjacency.get(relationship.targetEntityInstanceId).push({
        relationshipInstanceId:
          relationship.relationshipInstanceId,
        relationshipTypeId:
          relationship.relationshipTypeId,
        direction: "inbound",
        entityInstanceId:
          relationship.sourceEntityInstanceId
      });
    }

    return adjacency;
  }

  function traverse(startEntityId, adjacency, depth = 1) {
    const visited = new Set([startEntityId]);
    const queue = [{ id: startEntityId, depth: 0 }];
    const results = [];

    while (queue.length) {
      const current = queue.shift();

      if (current.depth >= depth) continue;

      for (const edge of adjacency.get(current.id) || []) {
        results.push({
          fromEntityInstanceId:
            current.id,
          ...edge,
          depth:
            current.depth + 1
        });

        if (!visited.has(edge.entityInstanceId)) {
          visited.add(edge.entityInstanceId);
          queue.push({
            id: edge.entityInstanceId,
            depth: current.depth + 1
          });
        }
      }
    }

    return results;
  }

  global.INFINICUS.DT.graphIndex =
    Object.freeze({ build, traverse });
})(window);

/* --- INFINICUS-DT-05-Business-Entity-Relationship-Graph-Engine/src/graph/integrity-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze(entities = [], relationships = []) {
    const entityIds =
      new Set(
        entities.map(item => item.entityInstanceId)
      );

    const unresolvedRelationships =
      relationships.filter(item =>
        !entityIds.has(item.sourceEntityInstanceId) ||
        !entityIds.has(item.targetEntityInstanceId)
      );

    const connected = new Set();

    for (const relationship of relationships) {
      connected.add(relationship.sourceEntityInstanceId);
      connected.add(relationship.targetEntityInstanceId);
    }

    const orphanEntities =
      entities.filter(item =>
        !connected.has(item.entityInstanceId)
      );

    return {
      valid:
        unresolvedRelationships.length === 0,
      unresolvedRelationships:
        unresolvedRelationships.map(structuredClone),
      orphanEntities:
        orphanEntities.map(structuredClone)
    };
  }

  global.INFINICUS.DT.graphIntegrityAnalyzer =
    Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-05-Business-Entity-Relationship-Graph-Engine/src/storage/graph-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_ENTITY_GRAPH";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        if (!db.objectStoreNames.contains("entities")) {
          const store =
            db.createObjectStore(
              "entities",
              { keyPath: "entityInstanceId" }
            );

          store.createIndex(
            "twinId",
            "twinId",
            { unique: false }
          );

          store.createIndex(
            "entityKey",
            "entityKey",
            { unique: false }
          );
        }

        if (!db.objectStoreNames.contains("relationships")) {
          const store =
            db.createObjectStore(
              "relationships",
              { keyPath: "relationshipInstanceId" }
            );

          store.createIndex(
            "twinId",
            "twinId",
            { unique: false }
          );
        }

        if (!db.objectStoreNames.contains("graph_builds")) {
          db.createObjectStore(
            "graph_builds",
            { keyPath: "graphBuildId" }
          );
        }

        if (!db.objectStoreNames.contains("organization_handoffs")) {
          db.createObjectStore(
            "organization_handoffs",
            { keyPath: "organizationHandoffId" }
          );
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(
        tx.objectStore(storeName).put(structuredClone(record))
      );
      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "GRAPH_STORAGE_ERROR",
        error?.message || "Graph storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(
        tx.objectStore(storeName).get(id)
      );

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "GRAPH_RECORD_NOT_FOUND",
            "Graph record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "GRAPH_STORAGE_ERROR",
        error?.message || "Graph retrieval failed."
      );
    }
  }

  async function listByTwin(storeName, twinId) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(
        tx.objectStore(storeName)
          .index("twinId")
          .getAll(twinId)
      );

      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure(
        "GRAPH_STORAGE_ERROR",
        error?.message || "Graph listing failed."
      );
    }
  }

  global.INFINICUS.DT.graphStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-05-Business-Entity-Relationship-Graph-Engine/src/engine/entity-relationship-graph-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function buildGraph({
    entityGraphHandoffId,
    entityInputs = [],
    relationshipInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .intelligenceIntakeEngine
        .getEntityGraphHandoff({
          entityGraphHandoffId
        });

    if (!handoff.ok) return handoff;

    const ontology =
      handoff.data.ontology;

    const entityTypes =
      new Map(
        ontology.entityTypes.map(item => [
          item.entityTypeId,
          item
        ])
      );

    const relationshipTypes =
      new Map(
        ontology.relationshipTypes.map(item => [
          item.relationshipTypeId,
          item
        ])
      );

    const entities = [];
    const rejectedEntities = [];

    for (const input of entityInputs) {
      const built =
        global.INFINICUS.DT
          .entityInstanceModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId,
            businessId:
              handoff.data.businessId,
            ontologyId:
              handoff.data.ontologyId
          });

      if (!built.ok) {
        rejectedEntities.push({
          input:
            runtime.clone(input),
          error:
            built.error
        });
        continue;
      }

      const validation =
        global.INFINICUS.DT
          .entityInstanceValidator
          .validate(
            built.data,
            entityTypes.get(
              built.data.entityTypeId
            )
          );

      if (!validation.valid) {
        rejectedEntities.push({
          input:
            runtime.clone(input),
          issues:
            validation.issues
        });
        continue;
      }

      entities.push(built.data);

      await global.INFINICUS.DT
        .graphStore
        .put("entities", built.data);

      runtime.registerEntity(
        built.data.entityInstanceId,
        built.data,
        {
          twinId:
            built.data.twinId,
          entityTypeId:
            built.data.entityTypeId
        }
      );
    }

    const entityById =
      new Map(
        entities.map(item => [
          item.entityInstanceId,
          item
        ])
      );

    const relationships = [];
    const rejectedRelationships = [];

    for (const input of relationshipInputs) {
      const built =
        global.INFINICUS.DT
          .relationshipInstanceModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) {
        rejectedRelationships.push({
          input:
            runtime.clone(input),
          error:
            built.error
        });
        continue;
      }

      const validation =
        global.INFINICUS.DT
          .relationshipInstanceValidator
          .validate({
            relationship:
              built.data,
            relationshipType:
              relationshipTypes.get(
                built.data.relationshipTypeId
              ),
            sourceEntity:
              entityById.get(
                built.data.sourceEntityInstanceId
              ),
            targetEntity:
              entityById.get(
                built.data.targetEntityInstanceId
              ),
            existingRelationships:
              relationships
          });

      if (!validation.valid) {
        rejectedRelationships.push({
          input:
            runtime.clone(input),
          issues:
            validation.issues
        });
        continue;
      }

      relationships.push(built.data);

      await global.INFINICUS.DT
        .graphStore
        .put(
          "relationships",
          built.data
        );
    }

    const integrity =
      global.INFINICUS.DT
        .graphIntegrityAnalyzer
        .analyze(
          entities,
          relationships
        );

    const graphBuild = {
      graphBuildId:
        runtime.createId("dt_graph_build"),
      entityGraphHandoffId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      ontologyId:
        handoff.data.ontologyId,
      entityCount:
        entities.length,
      relationshipCount:
        relationships.length,
      rejectedEntityCount:
        rejectedEntities.length,
      rejectedRelationshipCount:
        rejectedRelationships.length,
      integrity:
        runtime.clone(integrity),
      status:
        integrity.valid
          ? "completed"
          : "completed_with_issues",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .graphStore
      .put("graph_builds", graphBuild);

    const organizationHandoff = {
      organizationHandoffId:
        runtime.createId("dt_organization_handoff"),
      targetBlock: "DT-06",
      graphBuildId:
        graphBuild.graphBuildId,
      businessId:
        graphBuild.businessId,
      twinId:
        graphBuild.twinId,
      ontologyId:
        graphBuild.ontologyId,
      entities:
        entities.map(runtime.clone),
      relationships:
        relationships.map(runtime.clone),
      graphIntegrity:
        runtime.clone(integrity),
      sourceContext: {
        businessState:
          runtime.clone(handoff.data.businessState),
        domainStates:
          handoff.data.domainStates.map(runtime.clone),
        lineage:
          handoff.data.lineage.map(runtime.clone),
        confidence:
          runtime.clone(handoff.data.confidence),
        freshness:
          runtime.clone(handoff.data.freshness)
      },
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .graphStore
      .put(
        "organization_handoffs",
        organizationHandoff
      );

    await runtime.emit(
      "dt.entity_graph.completed",
      {
        graphBuild,
        organizationHandoffId:
          organizationHandoff.organizationHandoffId
      }
    );

    return runtime.success({
      graphBuild,
      entities,
      relationships,
      rejectedEntities,
      rejectedRelationships,
      organizationHandoff
    });
  }

  async function traverse({
    twinId,
    startEntityInstanceId,
    depth = 1
  } = {}) {
    const entities =
      await global.INFINICUS.DT
        .graphStore
        .listByTwin("entities", twinId);

    if (!entities.ok) return entities;

    const relationships =
      await global.INFINICUS.DT
        .graphStore
        .listByTwin(
          "relationships",
          twinId
        );

    if (!relationships.ok) {
      return relationships;
    }

    const adjacency =
      global.INFINICUS.DT
        .graphIndex
        .build(
          entities.data,
          relationships.data
        );

    return runtime.success(
      global.INFINICUS.DT
        .graphIndex
        .traverse(
          startEntityInstanceId,
          adjacency,
          Math.max(1, Number(depth || 1))
        )
    );
  }

  const api = Object.freeze({
    buildGraph,
    traverse,
    getEntity: ({ entityInstanceId }) =>
      global.INFINICUS.DT
        .graphStore
        .get("entities", entityInstanceId),
    getRelationship: ({ relationshipInstanceId }) =>
      global.INFINICUS.DT
        .graphStore
        .get(
          "relationships",
          relationshipInstanceId
        ),
    listTwinEntities: ({ twinId }) =>
      global.INFINICUS.DT
        .graphStore
        .listByTwin("entities", twinId),
    listTwinRelationships: ({ twinId }) =>
      global.INFINICUS.DT
        .graphStore
        .listByTwin(
          "relationships",
          twinId
        ),
    getOrganizationHandoff: ({ organizationHandoffId }) =>
      global.INFINICUS.DT
        .graphStore
        .get(
          "organization_handoffs",
          organizationHandoffId
        )
  });

  runtime.registerService(
    "dt.entity_relationship_graph",
    api,
    { block: "DT-05" }
  );

  runtime.registerRoute(
    "dt.entity_graph.build",
    buildGraph
  );

  runtime.registerRoute(
    "dt.entity_graph.traverse",
    traverse
  );

  global.INFINICUS.DT.entityRelationshipGraphEngine = api;
})(window);

