/* --- INFINICUS-DT-06-Organizational-Structure-Twin-Engine/src/validation/reporting-line-validator.js --- */
(function (global) {
  "use strict";

  function validate(positions = []) {
    const issues = [];
    const byId =
      new Map(
        positions.map(item => [
          item.positionId,
          item
        ])
      );

    for (const position of positions) {
      if (
        position.reportsToPositionId &&
        !byId.has(position.reportsToPositionId)
      ) {
        issues.push(
          `Unknown manager position: ${position.reportsToPositionId}`
        );
      }

      if (
        position.reportsToPositionId ===
        position.positionId
      ) {
        issues.push(
          `Position reports to itself: ${position.positionId}`
        );
      }
    }

    function hasCycle(startId) {
      const seen = new Set();
      let current = byId.get(startId);

      while (current?.reportsToPositionId) {
        if (seen.has(current.positionId)) {
          return true;
        }

        seen.add(current.positionId);
        current =
          byId.get(current.reportsToPositionId);
      }

      return false;
    }

    for (const position of positions) {
      if (hasCycle(position.positionId)) {
        issues.push(
          `Reporting cycle detected from position: ${position.positionId}`
        );
      }
    }

    return {
      valid: issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.reportingLineValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-06-Organizational-Structure-Twin-Engine/src/analysis/organization-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze(units = [], positions = []) {
    const directReports = new Map();

    for (const position of positions) {
      if (!position.reportsToPositionId) continue;

      if (!directReports.has(position.reportsToPositionId)) {
        directReports.set(position.reportsToPositionId, []);
      }

      directReports.get(position.reportsToPositionId)
        .push(position.positionId);
    }

    const spanOfControl =
      [...directReports.entries()]
        .map(([managerPositionId, reports]) => ({
          managerPositionId,
          directReportCount:
            reports.length,
          risk:
            reports.length > 10
              ? "overloaded"
              : reports.length < 2
                ? "underutilized"
                : "balanced"
        }));

    const vacantPositions =
      positions.filter(position =>
        !position.occupantEntityInstanceId ||
        position.status === "vacant"
      );

    const rootPositions =
      positions.filter(position =>
        !position.reportsToPositionId
      );

    function depth(positionId) {
      const byId =
        new Map(
          positions.map(item => [
            item.positionId,
            item
          ])
        );

      let level = 1;
      let current = byId.get(positionId);
      const seen = new Set();

      while (current?.reportsToPositionId) {
        if (seen.has(current.positionId)) break;

        seen.add(current.positionId);
        current =
          byId.get(current.reportsToPositionId);
        level += 1;
      }

      return level;
    }

    const maximumManagementLayers =
      positions.length
        ? Math.max(
            ...positions.map(position =>
              depth(position.positionId)
            )
          )
        : 0;

    const unitsWithoutLeaders =
      units.filter(unit =>
        !unit.leaderPositionId
      );

    return {
      spanOfControl,
      vacantPositions:
        vacantPositions.map(structuredClone),
      rootPositions:
        rootPositions.map(structuredClone),
      maximumManagementLayers,
      unitsWithoutLeaders:
        unitsWithoutLeaders.map(structuredClone)
    };
  }

  global.INFINICUS.DT.organizationAnalyzer =
    Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-06-Organizational-Structure-Twin-Engine/src/chart/organization-chart.js --- */
(function (global) {
  "use strict";

  function build(units = [], positions = [], roles = []) {
    const roleById =
      new Map(
        roles.map(role => [role.roleId, role])
      );

    const children = new Map();

    for (const position of positions) {
      const parent =
        position.reportsToPositionId || "__root__";

      if (!children.has(parent)) {
        children.set(parent, []);
      }

      children.get(parent).push(position);
    }

    function node(position) {
      return {
        positionId:
          position.positionId,
        role:
          roleById.get(position.roleId)?.name || "Unknown role",
        organizationUnitId:
          position.organizationUnitId,
        occupantEntityInstanceId:
          position.occupantEntityInstanceId,
        status:
          position.status,
        children:
          (children.get(position.positionId) || [])
            .map(node)
      };
    }

    return {
      units:
        units.map(structuredClone),
      roots:
        (children.get("__root__") || [])
          .map(node),
      generatedAt:
        new Date().toISOString()
    };
  }

  global.INFINICUS.DT.organizationChartBuilder =
    Object.freeze({ build });
})(window);

/* --- INFINICUS-DT-06-Organizational-Structure-Twin-Engine/src/storage/organization-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_ORGANIZATION";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        for (const [name, keyPath] of [
          ["units", "organizationUnitId"],
          ["roles", "roleId"],
          ["positions", "positionId"],
          ["organization_builds", "organizationBuildId"],
          ["financial_handoffs", "financialHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            const store =
              db.createObjectStore(name, { keyPath });

            if (
              ["units", "roles", "positions"]
                .includes(name)
            ) {
              store.createIndex(
                "twinId",
                "twinId",
                { unique: false }
              );
            }
          }
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(
        tx.objectStore(storeName).put(structuredClone(record))
      );

      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "ORGANIZATION_STORAGE_ERROR",
        error?.message || "Organization storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(
        tx.objectStore(storeName).get(id)
      );

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "ORGANIZATION_RECORD_NOT_FOUND",
            "Organization record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "ORGANIZATION_STORAGE_ERROR",
        error?.message || "Organization retrieval failed."
      );
    }
  }

  async function listByTwin(storeName, twinId) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(
        tx.objectStore(storeName)
          .index("twinId")
          .getAll(twinId)
      );

      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure(
        "ORGANIZATION_STORAGE_ERROR",
        error?.message || "Organization listing failed."
      );
    }
  }

  global.INFINICUS.DT.organizationStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-06-Organizational-Structure-Twin-Engine/src/engine/organizational-structure-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function buildOrganization({
    organizationHandoffId,
    unitInputs = [],
    roleInputs = [],
    positionInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .entityRelationshipGraphEngine
        .getOrganizationHandoff({
          organizationHandoffId
        });

    if (!handoff.ok) return handoff;

    const units = [];

    for (const input of unitInputs) {
      const built =
        global.INFINICUS.DT
          .organizationUnitModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      units.push(built.data);

      await global.INFINICUS.DT
        .organizationStore
        .put("units", built.data);
    }

    const roles = [];

    for (const input of roleInputs) {
      const built =
        global.INFINICUS.DT
          .rolePositionModel
          .createRole({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      roles.push(built.data);

      await global.INFINICUS.DT
        .organizationStore
        .put("roles", built.data);
    }

    const positions = [];

    for (const input of positionInputs) {
      const built =
        global.INFINICUS.DT
          .rolePositionModel
          .createPosition({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      positions.push(built.data);
    }

    const reportingValidation =
      global.INFINICUS.DT
        .reportingLineValidator
        .validate(positions);

    if (!reportingValidation.valid) {
      return runtime.failure(
        "REPORTING_STRUCTURE_INVALID",
        "Reporting-line validation failed.",
        reportingValidation
      );
    }

    const unitIds =
      new Set(
        units.map(unit =>
          unit.organizationUnitId
        )
      );

    const roleIds =
      new Set(
        roles.map(role =>
          role.roleId
        )
      );

    const referenceIssues = [];

    for (const position of positions) {
      if (!unitIds.has(position.organizationUnitId)) {
        referenceIssues.push(
          `Unknown organization unit: ${position.organizationUnitId}`
        );
      }

      if (!roleIds.has(position.roleId)) {
        referenceIssues.push(
          `Unknown role: ${position.roleId}`
        );
      }
    }

    if (referenceIssues.length) {
      return runtime.failure(
        "ORGANIZATION_REFERENCE_INVALID",
        "Organization references are invalid.",
        { issues: referenceIssues }
      );
    }

    for (const position of positions) {
      await global.INFINICUS.DT
        .organizationStore
        .put("positions", position);
    }

    const analysis =
      global.INFINICUS.DT
        .organizationAnalyzer
        .analyze(
          units,
          positions
        );

    const organizationChart =
      global.INFINICUS.DT
        .organizationChartBuilder
        .build(
          units,
          positions,
          roles
        );

    const organizationBuild = {
      organizationBuildId:
        runtime.createId("dt_organization_build"),
      organizationHandoffId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      unitCount:
        units.length,
      roleCount:
        roles.length,
      positionCount:
        positions.length,
      analysis:
        runtime.clone(analysis),
      organizationChart:
        runtime.clone(organizationChart),
      status: "completed",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .organizationStore
      .put(
        "organization_builds",
        organizationBuild
      );

    const financialHandoff = {
      financialHandoffId:
        runtime.createId("dt_financial_handoff"),
      targetBlock: "DT-07",
      organizationBuildId:
        organizationBuild.organizationBuildId,
      businessId:
        organizationBuild.businessId,
      twinId:
        organizationBuild.twinId,
      organizationUnits:
        units.map(runtime.clone),
      roles:
        roles.map(runtime.clone),
      positions:
        positions.map(runtime.clone),
      organizationAnalysis:
        runtime.clone(analysis),
      organizationChart:
        runtime.clone(organizationChart),
      sourceEntities:
        handoff.data.entities.map(runtime.clone),
      sourceRelationships:
        handoff.data.relationships.map(runtime.clone),
      sourceContext:
        runtime.clone(handoff.data.sourceContext),
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .organizationStore
      .put(
        "financial_handoffs",
        financialHandoff
      );

    await runtime.emit(
      "dt.organizational_structure.completed",
      {
        organizationBuild,
        financialHandoffId:
          financialHandoff.financialHandoffId
      }
    );

    return runtime.success({
      organizationBuild,
      units,
      roles,
      positions,
      financialHandoff
    });
  }

  const api = Object.freeze({
    buildOrganization,
    getOrganizationBuild: ({ organizationBuildId }) =>
      global.INFINICUS.DT
        .organizationStore
        .get(
          "organization_builds",
          organizationBuildId
        ),
    getFinancialHandoff: ({ financialHandoffId }) =>
      global.INFINICUS.DT
        .organizationStore
        .get(
          "financial_handoffs",
          financialHandoffId
        ),
    listTwinUnits: ({ twinId }) =>
      global.INFINICUS.DT
        .organizationStore
        .listByTwin("units", twinId),
    listTwinRoles: ({ twinId }) =>
      global.INFINICUS.DT
        .organizationStore
        .listByTwin("roles", twinId),
    listTwinPositions: ({ twinId }) =>
      global.INFINICUS.DT
        .organizationStore
        .listByTwin("positions", twinId)
  });

  runtime.registerService(
    "dt.organizational_structure",
    api,
    { block: "DT-06" }
  );

  runtime.registerRoute(
    "dt.organizational_structure.build",
    buildOrganization
  );

  global.INFINICUS.DT.organizationalStructureEngine = api;
})(window);

