/* --- INFINICUS-DT-07-Financial-State-Twin-Engine/src/analysis/financial-profile-builder.js --- */
(function (global) {
  "use strict";

  function latest(states = [], accounts = []) {
    const accountById =
      new Map(
        accounts.map(account => [
          account.financialAccountId,
          account
        ])
      );

    const sums = {
      assets: 0,
      liabilities: 0,
      equity: 0,
      revenue: 0,
      costs: 0,
      expenses: 0,
      cashFlow: 0,
      budgets: 0,
      targets: 0
    };

    for (const state of states) {
      const account =
        accountById.get(state.financialAccountId);

      if (!account) continue;

      const value = Number(state.value || 0);

      if (account.accountType === "asset") sums.assets += value;
      if (account.accountType === "liability") sums.liabilities += value;
      if (account.accountType === "equity") sums.equity += value;
      if (account.accountType === "revenue") sums.revenue += value;
      if (account.accountType === "cost") sums.costs += value;
      if (account.accountType === "expense") sums.expenses += value;
      if (account.accountType === "cash_flow") sums.cashFlow += value;
      if (account.accountType === "budget") sums.budgets += value;
      if (account.accountType === "target") sums.targets += value;
    }

    const grossProfit =
      sums.revenue - sums.costs;

    const operatingProfit =
      grossProfit - sums.expenses;

    return {
      ...sums,
      grossProfit:
        Number(grossProfit.toFixed(4)),
      operatingProfit:
        Number(operatingProfit.toFixed(4)),
      grossMarginPercent:
        sums.revenue === 0
          ? null
          : Number(
              (grossProfit / sums.revenue * 100)
                .toFixed(4)
            ),
      operatingMarginPercent:
        sums.revenue === 0
          ? null
          : Number(
              (operatingProfit / sums.revenue * 100)
                .toFixed(4)
            )
    };
  }

  global.INFINICUS.DT.financialProfileBuilder =
    Object.freeze({ latest });
})(window);

/* --- INFINICUS-DT-07-Financial-State-Twin-Engine/src/validation/financial-consistency.js --- */
(function (global) {
  "use strict";

  function validate({
    accounts = [],
    states = []
  } = {}) {
    const issues = [];
    const currencies =
      new Set(states.map(state => state.currency));

    if (currencies.size > 1) {
      issues.push(
        "Multiple currencies are present without a conversion policy."
      );
    }

    const profile =
      global.INFINICUS.DT
        .financialProfileBuilder
        .latest(states, accounts);

    const balanceDifference =
      profile.assets -
      (profile.liabilities + profile.equity);

    if (Math.abs(balanceDifference) > 0.01) {
      issues.push(
        `Balance equation mismatch: ${balanceDifference.toFixed(2)}`
      );
    }

    const invalidConfidence =
      states.filter(state =>
        state.confidence < 0 ||
        state.confidence > 1
      );

    if (invalidConfidence.length) {
      issues.push(
        "One or more financial states have invalid confidence values."
      );
    }

    return {
      valid:
        issues.length === 0,
      issues,
      profile,
      balanceDifference:
        Number(balanceDifference.toFixed(4))
    };
  }

  global.INFINICUS.DT.financialConsistencyValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-07-Financial-State-Twin-Engine/src/storage/financial-state-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_FINANCIAL_STATE";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        for (const [name, keyPath] of [
          ["accounts", "financialAccountId"],
          ["states", "financialStateId"],
          ["snapshots", "financialSnapshotId"],
          ["customer_handoffs", "customerHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            const store =
              db.createObjectStore(name, { keyPath });

            if (
              ["accounts", "states"]
                .includes(name)
            ) {
              store.createIndex(
                "twinId",
                "twinId",
                { unique: false }
              );
            }
          }
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(
        tx.objectStore(storeName).put(structuredClone(record))
      );
      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "FINANCIAL_STATE_STORAGE_ERROR",
        error?.message || "Financial state storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(
        tx.objectStore(storeName).get(id)
      );

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "FINANCIAL_STATE_RECORD_NOT_FOUND",
            "Financial state record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "FINANCIAL_STATE_STORAGE_ERROR",
        error?.message || "Financial state retrieval failed."
      );
    }
  }

  async function listByTwin(storeName, twinId) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(
        tx.objectStore(storeName)
          .index("twinId")
          .getAll(twinId)
      );

      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure(
        "FINANCIAL_STATE_STORAGE_ERROR",
        error?.message || "Financial state listing failed."
      );
    }
  }

  global.INFINICUS.DT.financialStateStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-07-Financial-State-Twin-Engine/src/engine/financial-state-twin-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function buildFinancialState({
    financialHandoffId,
    accountInputs = [],
    stateInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .organizationalStructureEngine
        .getFinancialHandoff({
          financialHandoffId
        });

    if (!handoff.ok) return handoff;

    const unitIds =
      new Set(
        handoff.data.organizationUnits
          .map(unit => unit.organizationUnitId)
      );

    const accounts = [];

    for (const input of accountInputs) {
      if (
        input.organizationUnitId &&
        !unitIds.has(input.organizationUnitId)
      ) {
        return runtime.failure(
          "FINANCIAL_ACCOUNT_UNIT_INVALID",
          `Unknown organization unit: ${input.organizationUnitId}`
        );
      }

      const built =
        global.INFINICUS.DT
          .financialAccountModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      accounts.push(built.data);

      await global.INFINICUS.DT
        .financialStateStore
        .put("accounts", built.data);
    }

    const accountIds =
      new Set(
        accounts.map(account =>
          account.financialAccountId
        )
      );

    const states = [];

    for (const input of stateInputs) {
      if (
        !accountIds.has(input.financialAccountId)
      ) {
        return runtime.failure(
          "FINANCIAL_STATE_ACCOUNT_INVALID",
          `Unknown financial account: ${input.financialAccountId}`
        );
      }

      const built =
        global.INFINICUS.DT
          .financialStateModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      states.push(built.data);

      await global.INFINICUS.DT
        .financialStateStore
        .put("states", built.data);
    }

    const consistency =
      global.INFINICUS.DT
        .financialConsistencyValidator
        .validate({
          accounts,
          states
        });

    const snapshot = {
      financialSnapshotId:
        runtime.createId("dt_financial_snapshot"),
      financialHandoffId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      accounts:
        accounts.map(runtime.clone),
      states:
        states.map(runtime.clone),
      profile:
        runtime.clone(consistency.profile),
      consistency:
        runtime.clone(consistency),
      organizationContext: {
        units:
          handoff.data.organizationUnits.map(runtime.clone),
        roles:
          handoff.data.roles.map(runtime.clone),
        positions:
          handoff.data.positions.map(runtime.clone)
      },
      status:
        consistency.valid
          ? "current"
          : "current_with_issues",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .financialStateStore
      .put("snapshots", snapshot);

    const customerHandoff = {
      customerHandoffId:
        runtime.createId("dt_customer_handoff"),
      targetBlock: "DT-08",
      financialSnapshotId:
        snapshot.financialSnapshotId,
      businessId:
        snapshot.businessId,
      twinId:
        snapshot.twinId,
      financialProfile:
        runtime.clone(snapshot.profile),
      financialConsistency:
        runtime.clone(snapshot.consistency),
      organizationContext:
        runtime.clone(snapshot.organizationContext),
      sourceEntities:
        handoff.data.sourceEntities.map(runtime.clone),
      sourceRelationships:
        handoff.data.sourceRelationships.map(runtime.clone),
      sourceContext:
        runtime.clone(handoff.data.sourceContext),
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .financialStateStore
      .put(
        "customer_handoffs",
        customerHandoff
      );

    await runtime.emit(
      "dt.financial_state.completed",
      {
        financialSnapshot:
          snapshot,
        customerHandoffId:
          customerHandoff.customerHandoffId
      }
    );

    return runtime.success({
      financialSnapshot:
        snapshot,
      customerHandoff
    });
  }

  const api = Object.freeze({
    buildFinancialState,
    getFinancialSnapshot: ({ financialSnapshotId }) =>
      global.INFINICUS.DT
        .financialStateStore
        .get(
          "snapshots",
          financialSnapshotId
        ),
    getCustomerHandoff: ({ customerHandoffId }) =>
      global.INFINICUS.DT
        .financialStateStore
        .get(
          "customer_handoffs",
          customerHandoffId
        ),
    listTwinAccounts: ({ twinId }) =>
      global.INFINICUS.DT
        .financialStateStore
        .listByTwin("accounts", twinId),
    listTwinFinancialStates: ({ twinId }) =>
      global.INFINICUS.DT
        .financialStateStore
        .listByTwin("states", twinId)
  });

  runtime.registerService(
    "dt.financial_state_twin",
    api,
    { block: "DT-07" }
  );

  runtime.registerRoute(
    "dt.financial_state.build",
    buildFinancialState
  );

  global.INFINICUS.DT.financialStateTwinEngine = api;
})(window);

