/* --- INFINICUS-DT-08-Customer-Demand-Twin-Engine/src/model/demand-state.js --- */
(function (global) {
  "use strict";

  function create(input = {}) {
    const runtime = global.INFINICUS.DT.runtime;

    if (
      !input.twinId ||
      !input.period
    ) {
      return runtime.failure(
        "DEMAND_STATE_INVALID",
        "twinId and period are required."
      );
    }

    return runtime.success({
      demandStateId:
        input.demandStateId ||
        runtime.createId("dt_demand_state"),
      twinId:
        String(input.twinId),
      customerProfileId:
        input.customerProfileId || null,
      customerSegmentId:
        input.customerSegmentId || null,
      cohortId:
        input.cohortId || null,
      period:
        String(input.period),
      demandUnits:
        Number(input.demandUnits || 0),
      revenueValue:
        Number(input.revenueValue || 0),
      retentionRatePercent:
        input.retentionRatePercent == null
          ? null
          : Number(input.retentionRatePercent),
      churnRatePercent:
        input.churnRatePercent == null
          ? null
          : Number(input.churnRatePercent),
      purchaseFrequency:
        input.purchaseFrequency == null
          ? null
          : Number(input.purchaseFrequency),
      lifetimeValue:
        input.lifetimeValue == null
          ? null
          : Number(input.lifetimeValue),
      satisfactionScore:
        input.satisfactionScore == null
          ? null
          : Number(input.satisfactionScore),
      advocacyScore:
        input.advocacyScore == null
          ? null
          : Number(input.advocacyScore),
      sourceType:
        String(input.sourceType || "observed"),
      sourceReferences:
        runtime.clone(input.sourceReferences || []),
      lineage:
        runtime.clone(input.lineage || []),
      confidence:
        Number(input.confidence ?? 1),
      createdAt:
        new Date().toISOString()
    });
  }

  global.INFINICUS.DT.demandStateModel =
    Object.freeze({ create });
})(window);

/* --- INFINICUS-DT-08-Customer-Demand-Twin-Engine/src/analysis/customer-demand-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze(states = []) {
    const totalDemand =
      states.reduce(
        (sum, state) =>
          sum + Number(state.demandUnits || 0),
        0
      );

    const totalRevenue =
      states.reduce(
        (sum, state) =>
          sum + Number(state.revenueValue || 0),
        0
      );

    const weighted = (field, weightField = "demandUnits") => {
      const usable =
        states.filter(state =>
          Number.isFinite(Number(state[field]))
        );

      const weight =
        usable.reduce(
          (sum, state) =>
            sum + Math.max(
              0,
              Number(state[weightField] || 0)
            ),
          0
        );

      if (!usable.length) return null;

      if (weight === 0) {
        return Number((
          usable.reduce(
            (sum, state) =>
              sum + Number(state[field]),
            0
          ) / usable.length
        ).toFixed(4));
      }

      return Number((
        usable.reduce(
          (sum, state) =>
            sum +
            Number(state[field]) *
            Math.max(
              0,
              Number(state[weightField] || 0)
            ),
          0
        ) / weight
      ).toFixed(4));
    };

    const grouped =
      new Map();

    for (const state of states) {
      const key =
        state.customerSegmentId ||
        state.customerProfileId ||
        "unclassified";

      if (!grouped.has(key)) {
        grouped.set(key, 0);
      }

      grouped.set(
        key,
        grouped.get(key) +
        Number(state.revenueValue || 0)
      );
    }

    const concentration =
      totalRevenue === 0
        ? []
        : [...grouped.entries()]
            .map(([key, revenue]) => ({
              key,
              revenue:
                Number(revenue.toFixed(4)),
              sharePercent:
                Number(
                  (revenue / totalRevenue * 100)
                    .toFixed(4)
                )
            }))
            .sort((a, b) =>
              b.sharePercent - a.sharePercent
            );

    return {
      totalDemand:
        Number(totalDemand.toFixed(4)),
      totalRevenue:
        Number(totalRevenue.toFixed(4)),
      retentionRatePercent:
        weighted("retentionRatePercent"),
      churnRatePercent:
        weighted("churnRatePercent"),
      purchaseFrequency:
        weighted("purchaseFrequency"),
      lifetimeValue:
        weighted("lifetimeValue"),
      satisfactionScore:
        weighted("satisfactionScore"),
      advocacyScore:
        weighted("advocacyScore"),
      concentration
    };
  }

  global.INFINICUS.DT.customerDemandAnalyzer =
    Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-08-Customer-Demand-Twin-Engine/src/validation/customer-demand-validator.js --- */
(function (global) {
  "use strict";

  function validate({
    profiles = [],
    segments = [],
    states = []
  } = {}) {
    const issues = [];
    const profileIds =
      new Set(
        profiles.map(profile =>
          profile.customerProfileId
        )
      );

    const segmentIds =
      new Set(
        segments.map(segment =>
          segment.customerSegmentId
        )
      );

    for (const state of states) {
      if (
        state.customerProfileId &&
        !profileIds.has(state.customerProfileId)
      ) {
        issues.push(
          `Unknown customer profile: ${state.customerProfileId}`
        );
      }

      if (
        state.customerSegmentId &&
        !segmentIds.has(state.customerSegmentId)
      ) {
        issues.push(
          `Unknown customer segment: ${state.customerSegmentId}`
        );
      }

      for (const field of [
        "retentionRatePercent",
        "churnRatePercent"
      ]) {
        if (
          state[field] != null &&
          (
            state[field] < 0 ||
            state[field] > 100
          )
        ) {
          issues.push(
            `${field} must be between 0 and 100.`
          );
        }
      }

      if (
        state.confidence < 0 ||
        state.confidence > 1
      ) {
        issues.push(
          "Demand-state confidence must be between 0 and 1."
        );
      }
    }

    return {
      valid:
        issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.customerDemandValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-08-Customer-Demand-Twin-Engine/src/storage/customer-demand-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_CUSTOMER_DEMAND";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        for (const [name, keyPath] of [
          ["profiles", "customerProfileId"],
          ["segments", "customerSegmentId"],
          ["states", "demandStateId"],
          ["snapshots", "customerDemandSnapshotId"],
          ["sales_handoffs", "salesHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            const store =
              db.createObjectStore(name, { keyPath });

            if (
              ["profiles", "segments", "states"]
                .includes(name)
            ) {
              store.createIndex(
                "twinId",
                "twinId",
                { unique: false }
              );
            }
          }
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(
        tx.objectStore(storeName).put(structuredClone(record))
      );

      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "CUSTOMER_DEMAND_STORAGE_ERROR",
        error?.message || "Customer demand storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(
        tx.objectStore(storeName).get(id)
      );

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "CUSTOMER_DEMAND_RECORD_NOT_FOUND",
            "Customer demand record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "CUSTOMER_DEMAND_STORAGE_ERROR",
        error?.message || "Customer demand retrieval failed."
      );
    }
  }

  async function listByTwin(storeName, twinId) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(
        tx.objectStore(storeName)
          .index("twinId")
          .getAll(twinId)
      );

      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure(
        "CUSTOMER_DEMAND_STORAGE_ERROR",
        error?.message || "Customer demand listing failed."
      );
    }
  }

  global.INFINICUS.DT.customerDemandStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-08-Customer-Demand-Twin-Engine/src/engine/customer-demand-twin-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function buildCustomerDemandState({
    customerHandoffId,
    profileInputs = [],
    segmentInputs = [],
    stateInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .financialStateTwinEngine
        .getCustomerHandoff({
          customerHandoffId
        });

    if (!handoff.ok) return handoff;

    const segments = [];

    for (const input of segmentInputs) {
      const built =
        global.INFINICUS.DT
          .customerSegmentModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      segments.push(built.data);

      await global.INFINICUS.DT
        .customerDemandStore
        .put("segments", built.data);
    }

    const profiles = [];

    for (const input of profileInputs) {
      const built =
        global.INFINICUS.DT
          .customerProfileModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      profiles.push(built.data);

      await global.INFINICUS.DT
        .customerDemandStore
        .put("profiles", built.data);
    }

    const states = [];

    for (const input of stateInputs) {
      const built =
        global.INFINICUS.DT
          .demandStateModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      states.push(built.data);
    }

    const validation =
      global.INFINICUS.DT
        .customerDemandValidator
        .validate({
          profiles,
          segments,
          states
        });

    if (!validation.valid) {
      return runtime.failure(
        "CUSTOMER_DEMAND_STATE_INVALID",
        "Customer and demand validation failed.",
        validation
      );
    }

    for (const state of states) {
      await global.INFINICUS.DT
        .customerDemandStore
        .put("states", state);
    }

    const analysis =
      global.INFINICUS.DT
        .customerDemandAnalyzer
        .analyze(states);

    const snapshot = {
      customerDemandSnapshotId:
        runtime.createId("dt_customer_demand_snapshot"),
      customerHandoffId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      profiles:
        profiles.map(runtime.clone),
      segments:
        segments.map(runtime.clone),
      states:
        states.map(runtime.clone),
      analysis:
        runtime.clone(analysis),
      financialProfile:
        runtime.clone(handoff.data.financialProfile),
      status: "current",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .customerDemandStore
      .put("snapshots", snapshot);

    const salesHandoff = {
      salesHandoffId:
        runtime.createId("dt_sales_handoff"),
      targetBlock: "DT-09",
      customerDemandSnapshotId:
        snapshot.customerDemandSnapshotId,
      financialSnapshotId:
        handoff.data.financialSnapshotId,
      businessId:
        snapshot.businessId,
      twinId:
        snapshot.twinId,
      customerProfiles:
        profiles.map(runtime.clone),
      customerSegments:
        segments.map(runtime.clone),
      demandStates:
        states.map(runtime.clone),
      customerDemandAnalysis:
        runtime.clone(analysis),
      financialProfile:
        runtime.clone(handoff.data.financialProfile),
      organizationContext:
        runtime.clone(handoff.data.organizationContext),
      sourceEntities:
        handoff.data.sourceEntities.map(runtime.clone),
      sourceRelationships:
        handoff.data.sourceRelationships.map(runtime.clone),
      sourceContext:
        runtime.clone(handoff.data.sourceContext),
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .customerDemandStore
      .put("sales_handoffs", salesHandoff);

    await runtime.emit(
      "dt.customer_demand.completed",
      {
        customerDemandSnapshot:
          snapshot,
        salesHandoffId:
          salesHandoff.salesHandoffId
      }
    );

    return runtime.success({
      customerDemandSnapshot:
        snapshot,
      salesHandoff
    });
  }

  const api = Object.freeze({
    buildCustomerDemandState,
    getCustomerDemandSnapshot: ({ customerDemandSnapshotId }) =>
      global.INFINICUS.DT
        .customerDemandStore
        .get(
          "snapshots",
          customerDemandSnapshotId
        ),
    getSalesHandoff: ({ salesHandoffId }) =>
      global.INFINICUS.DT
        .customerDemandStore
        .get(
          "sales_handoffs",
          salesHandoffId
        ),
    listTwinCustomerProfiles: ({ twinId }) =>
      global.INFINICUS.DT
        .customerDemandStore
        .listByTwin("profiles", twinId),
    listTwinCustomerSegments: ({ twinId }) =>
      global.INFINICUS.DT
        .customerDemandStore
        .listByTwin("segments", twinId),
    listTwinDemandStates: ({ twinId }) =>
      global.INFINICUS.DT
        .customerDemandStore
        .listByTwin("states", twinId)
  });

  runtime.registerService(
    "dt.customer_demand_twin",
    api,
    { block: "DT-08" }
  );

  runtime.registerRoute(
    "dt.customer_demand.build",
    buildCustomerDemandState
  );

  global.INFINICUS.DT.customerDemandTwinEngine = api;
})(window);

