/* --- INFINICUS-DT-09-Sales-Revenue-Flow-Twin-Engine/src/analysis/sales-flow-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze({
    stages = [],
    opportunities = [],
    orders = []
  } = {}) {
    const stageById =
      new Map(stages.map(stage => [stage.pipelineStageId, stage]));

    const openOpportunities =
      opportunities.filter(item => item.status === "open");

    const weightedPipeline =
      openOpportunities.reduce((sum, opportunity) => {
        const stage =
          stageById.get(opportunity.pipelineStageId);

        const probability =
          Number(stage?.probabilityPercent || 0) / 100;

        return sum +
          Number(opportunity.expectedValue || 0) *
          probability;
      }, 0);

    const totalPipeline =
      openOpportunities.reduce(
        (sum, opportunity) =>
          sum + Number(opportunity.expectedValue || 0),
        0
      );

    const totalRevenue =
      orders
        .filter(order =>
          !["cancelled", "refunded"].includes(order.status)
        )
        .reduce(
          (sum, order) =>
            sum + Number(order.value || 0),
          0
        );

    const recurringRevenue =
      orders
        .filter(order =>
          order.recurring &&
          !["cancelled", "refunded"].includes(order.status)
        )
        .reduce(
          (sum, order) =>
            sum + Number(order.value || 0),
          0
        );

    const won =
      opportunities.filter(item =>
        item.status === "won"
      ).length;

    const lost =
      opportunities.filter(item =>
        item.status === "lost"
      ).length;

    const conversionRatePercent =
      won + lost === 0
        ? null
        : Number(
            (won / (won + lost) * 100)
              .toFixed(4)
          );

    const closed =
      opportunities.filter(item =>
        item.closedAt && item.openedAt
      );

    const averageSalesCycleDays =
      closed.length === 0
        ? null
        : Number((
            closed.reduce((sum, item) =>
              sum +
              (
                new Date(item.closedAt).getTime() -
                new Date(item.openedAt).getTime()
              ) / 86400000,
            0) / closed.length
          ).toFixed(4));

    return {
      totalPipeline:
        Number(totalPipeline.toFixed(4)),
      weightedPipeline:
        Number(weightedPipeline.toFixed(4)),
      totalRevenue:
        Number(totalRevenue.toFixed(4)),
      recurringRevenue:
        Number(recurringRevenue.toFixed(4)),
      opportunityCount:
        opportunities.length,
      openOpportunityCount:
        openOpportunities.length,
      wonCount:
        won,
      lostCount:
        lost,
      conversionRatePercent,
      averageSalesCycleDays
    };
  }

  global.INFINICUS.DT.salesFlowAnalyzer =
    Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-09-Sales-Revenue-Flow-Twin-Engine/src/validation/sales-flow-validator.js --- */
(function (global) {
  "use strict";

  function validate({
    stages = [],
    opportunities = [],
    orders = [],
    customerProfiles = []
  } = {}) {
    const issues = [];
    const stageIds =
      new Set(stages.map(item => item.pipelineStageId));
    const opportunityIds =
      new Set(opportunities.map(item => item.opportunityId));
    const customerIds =
      new Set(customerProfiles.map(item => item.customerProfileId));

    for (const opportunity of opportunities) {
      if (!stageIds.has(opportunity.pipelineStageId)) {
        issues.push(
          `Unknown pipeline stage: ${opportunity.pipelineStageId}`
        );
      }

      if (
        opportunity.customerProfileId &&
        !customerIds.has(opportunity.customerProfileId)
      ) {
        issues.push(
          `Unknown customer profile: ${opportunity.customerProfileId}`
        );
      }

      if (
        opportunity.confidence < 0 ||
        opportunity.confidence > 1
      ) {
        issues.push(
          "Opportunity confidence must be between 0 and 1."
        );
      }
    }

    for (const order of orders) {
      if (
        order.opportunityId &&
        !opportunityIds.has(order.opportunityId)
      ) {
        issues.push(
          `Unknown opportunity: ${order.opportunityId}`
        );
      }

      if (
        order.customerProfileId &&
        !customerIds.has(order.customerProfileId)
      ) {
        issues.push(
          `Unknown customer profile: ${order.customerProfileId}`
        );
      }
    }

    return {
      valid:
        issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.salesFlowValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-09-Sales-Revenue-Flow-Twin-Engine/src/storage/sales-flow-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_SALES_REVENUE_FLOW";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        for (const [name, keyPath] of [
          ["stages", "pipelineStageId"],
          ["opportunities", "opportunityId"],
          ["orders", "orderId"],
          ["revenue_streams", "revenueStreamId"],
          ["snapshots", "salesRevenueSnapshotId"],
          ["marketing_handoffs", "marketingHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            const store =
              db.createObjectStore(name, { keyPath });

            if (
              ["stages", "opportunities", "orders", "revenue_streams"]
                .includes(name)
            ) {
              store.createIndex(
                "twinId",
                "twinId",
                { unique: false }
              );
            }
          }
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(
        tx.objectStore(storeName).put(structuredClone(record))
      );
      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "SALES_FLOW_STORAGE_ERROR",
        error?.message || "Sales flow storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(
        tx.objectStore(storeName).get(id)
      );

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "SALES_FLOW_RECORD_NOT_FOUND",
            "Sales flow record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "SALES_FLOW_STORAGE_ERROR",
        error?.message || "Sales flow retrieval failed."
      );
    }
  }

  async function listByTwin(storeName, twinId) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(
        tx.objectStore(storeName)
          .index("twinId")
          .getAll(twinId)
      );
      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure(
        "SALES_FLOW_STORAGE_ERROR",
        error?.message || "Sales flow listing failed."
      );
    }
  }

  global.INFINICUS.DT.salesFlowStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-09-Sales-Revenue-Flow-Twin-Engine/src/engine/sales-revenue-flow-twin-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function buildSalesRevenueFlow({
    salesHandoffId,
    stageInputs = [],
    opportunityInputs = [],
    orderInputs = [],
    revenueStreamInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .customerDemandTwinEngine
        .getSalesHandoff({
          salesHandoffId
        });

    if (!handoff.ok) return handoff;

    const stages = [];

    for (const input of stageInputs) {
      const built =
        global.INFINICUS.DT
          .pipelineStageModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      stages.push(built.data);

      await global.INFINICUS.DT
        .salesFlowStore
        .put("stages", built.data);
    }

    const opportunities = [];

    for (const input of opportunityInputs) {
      const built =
        global.INFINICUS.DT
          .opportunityModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      opportunities.push(built.data);
    }

    const orders = [];

    for (const input of orderInputs) {
      const built =
        global.INFINICUS.DT
          .orderRevenueModel
          .createOrder({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      orders.push(built.data);
    }

    const validation =
      global.INFINICUS.DT
        .salesFlowValidator
        .validate({
          stages,
          opportunities,
          orders,
          customerProfiles:
            handoff.data.customerProfiles
        });

    if (!validation.valid) {
      return runtime.failure(
        "SALES_REVENUE_FLOW_INVALID",
        "Sales and revenue-flow validation failed.",
        validation
      );
    }

    for (const opportunity of opportunities) {
      await global.INFINICUS.DT
        .salesFlowStore
        .put("opportunities", opportunity);
    }

    for (const order of orders) {
      await global.INFINICUS.DT
        .salesFlowStore
        .put("orders", order);
    }

    const revenueStreams = [];

    for (const input of revenueStreamInputs) {
      const built =
        global.INFINICUS.DT
          .orderRevenueModel
          .createRevenueStream({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      revenueStreams.push(built.data);

      await global.INFINICUS.DT
        .salesFlowStore
        .put("revenue_streams", built.data);
    }

    const analysis =
      global.INFINICUS.DT
        .salesFlowAnalyzer
        .analyze({
          stages,
          opportunities,
          orders
        });

    const snapshot = {
      salesRevenueSnapshotId:
        runtime.createId("dt_sales_revenue_snapshot"),
      salesHandoffId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      stages:
        stages.map(runtime.clone),
      opportunities:
        opportunities.map(runtime.clone),
      orders:
        orders.map(runtime.clone),
      revenueStreams:
        revenueStreams.map(runtime.clone),
      analysis:
        runtime.clone(analysis),
      customerDemandAnalysis:
        runtime.clone(
          handoff.data.customerDemandAnalysis
        ),
      status: "current",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .salesFlowStore
      .put("snapshots", snapshot);

    const marketingHandoff = {
      marketingHandoffId:
        runtime.createId("dt_marketing_handoff"),
      targetBlock: "DT-10",
      salesRevenueSnapshotId:
        snapshot.salesRevenueSnapshotId,
      customerDemandSnapshotId:
        handoff.data.customerDemandSnapshotId,
      financialSnapshotId:
        handoff.data.financialSnapshotId,
      businessId:
        snapshot.businessId,
      twinId:
        snapshot.twinId,
      salesAnalysis:
        runtime.clone(analysis),
      stages:
        stages.map(runtime.clone),
      opportunities:
        opportunities.map(runtime.clone),
      orders:
        orders.map(runtime.clone),
      revenueStreams:
        revenueStreams.map(runtime.clone),
      customerProfiles:
        handoff.data.customerProfiles.map(runtime.clone),
      customerSegments:
        handoff.data.customerSegments.map(runtime.clone),
      demandStates:
        handoff.data.demandStates.map(runtime.clone),
      financialProfile:
        runtime.clone(handoff.data.financialProfile),
      sourceContext:
        runtime.clone(handoff.data.sourceContext),
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .salesFlowStore
      .put(
        "marketing_handoffs",
        marketingHandoff
      );

    await runtime.emit(
      "dt.sales_revenue_flow.completed",
      {
        salesRevenueSnapshot:
          snapshot,
        marketingHandoffId:
          marketingHandoff.marketingHandoffId
      }
    );

    return runtime.success({
      salesRevenueSnapshot:
        snapshot,
      marketingHandoff
    });
  }

  const api = Object.freeze({
    buildSalesRevenueFlow,
    getSalesRevenueSnapshot: ({ salesRevenueSnapshotId }) =>
      global.INFINICUS.DT
        .salesFlowStore
        .get(
          "snapshots",
          salesRevenueSnapshotId
        ),
    getMarketingHandoff: ({ marketingHandoffId }) =>
      global.INFINICUS.DT
        .salesFlowStore
        .get(
          "marketing_handoffs",
          marketingHandoffId
        ),
    listTwinOpportunities: ({ twinId }) =>
      global.INFINICUS.DT
        .salesFlowStore
        .listByTwin("opportunities", twinId),
    listTwinOrders: ({ twinId }) =>
      global.INFINICUS.DT
        .salesFlowStore
        .listByTwin("orders", twinId),
    listTwinRevenueStreams: ({ twinId }) =>
      global.INFINICUS.DT
        .salesFlowStore
        .listByTwin("revenue_streams", twinId)
  });

  runtime.registerService(
    "dt.sales_revenue_flow_twin",
    api,
    { block: "DT-09" }
  );

  runtime.registerRoute(
    "dt.sales_revenue_flow.build",
    buildSalesRevenueFlow
  );

  global.INFINICUS.DT.salesRevenueFlowTwinEngine = api;
})(window);

