/* --- INFINICUS-DT-11-Operations-Process-Twin-Engine/src/analysis/operations-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze({ stages = [], resources = [], workItems = [] } = {}) {
    const completed = workItems.filter(item => item.completedAt);
    const queue = workItems.filter(item => !item.completedAt && item.status !== "cancelled");

    const cycleTimes = completed.map(item =>
      (new Date(item.completedAt).getTime() - new Date(item.enteredAt).getTime()) / 60000
    ).filter(Number.isFinite);

    const throughput = completed.length;
    const averageCycleTimeMinutes = cycleTimes.length
      ? Number((cycleTimes.reduce((a,b) => a+b, 0) / cycleTimes.length).toFixed(4))
      : null;

    const totalCapacity = resources.reduce((sum, item) =>
      sum + Number(item.capacity || 0) * Number(item.availabilityPercent || 0) / 100, 0);

    const utilizationPercent = totalCapacity === 0
      ? null
      : Number((throughput / totalCapacity * 100).toFixed(4));

    const defectRatePercent = workItems.length === 0
      ? null
      : Number((workItems.filter(item => item.defect).length / workItems.length * 100).toFixed(4));

    const reworkRatePercent = workItems.length === 0
      ? null
      : Number((workItems.filter(item => item.rework).length / workItems.length * 100).toFixed(4));

    const slaKnown = workItems.filter(item => item.slaMet != null);
    const slaCompliancePercent = slaKnown.length === 0
      ? null
      : Number((slaKnown.filter(item => item.slaMet).length / slaKnown.length * 100).toFixed(4));

    const queueByStage = new Map();
    for (const item of queue) {
      queueByStage.set(item.processStageId, (queueByStage.get(item.processStageId) || 0) + 1);
    }

    const bottlenecks = [...queueByStage.entries()]
      .map(([processStageId, queueLength]) => ({ processStageId, queueLength }))
      .sort((a,b) => b.queueLength - a.queueLength);

    return {
      throughput,
      queueLength: queue.length,
      averageCycleTimeMinutes,
      totalEffectiveCapacity: Number(totalCapacity.toFixed(4)),
      utilizationPercent,
      defectRatePercent,
      reworkRatePercent,
      slaCompliancePercent,
      bottlenecks,
      stageCount: stages.length,
      resourceCount: resources.length
    };
  }

  global.INFINICUS.DT.operationsAnalyzer = Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-11-Operations-Process-Twin-Engine/src/validation/operations-validator.js --- */
(function (global) {
  "use strict";

  function validate({ processes = [], stages = [], resources = [], workItems = [] } = {}) {
    const issues = [];
    const processIds = new Set(processes.map(item => item.processId));
    const stageIds = new Set(stages.map(item => item.processStageId));

    for (const stage of stages) {
      if (!processIds.has(stage.processId)) issues.push(`Unknown process: ${stage.processId}`);
      for (const predecessor of stage.predecessorStageIds) {
        if (!stageIds.has(predecessor)) issues.push(`Unknown predecessor stage: ${predecessor}`);
      }
    }

    for (const resource of resources) {
      for (const stageId of resource.processStageIds) {
        if (!stageIds.has(stageId)) issues.push(`Unknown resource stage: ${stageId}`);
      }
    }

    for (const item of workItems) {
      if (!processIds.has(item.processId)) issues.push(`Unknown work-item process: ${item.processId}`);
      if (!stageIds.has(item.processStageId)) issues.push(`Unknown work-item stage: ${item.processStageId}`);
      if (item.confidence < 0 || item.confidence > 1) issues.push("Work-item confidence must be between 0 and 1.");
    }

    return { valid: issues.length === 0, issues };
  }

  global.INFINICUS.DT.operationsValidator = Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-11-Operations-Process-Twin-Engine/src/storage/operations-store.js --- */
(function (global) {
  "use strict";
  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_OPERATIONS_PROCESS";
  let dbPromise;
  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;
    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);
      req.onupgradeneeded = () => {
        const db = req.result;
        for (const [name, keyPath] of [
          ["processes", "processId"],
          ["stages", "processStageId"],
          ["resources", "resourceId"],
          ["work_items", "workItemId"],
          ["snapshots", "operationsSnapshotId"],
          ["inventory_handoffs", "inventoryHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            const store = db.createObjectStore(name, { keyPath });
            if (["processes","stages","resources","work_items"].includes(name)) {
              store.createIndex("twinId", "twinId", { unique: false });
            }
          }
        }
      };
      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });
    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(tx.objectStore(storeName).put(structuredClone(record)));
      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure("OPERATIONS_STORAGE_ERROR", error?.message || "Operations storage failed.");
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(tx.objectStore(storeName).get(id));
      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure("OPERATIONS_RECORD_NOT_FOUND", "Operations record was not found.", { storeName, id });
    } catch (error) {
      return runtime.failure("OPERATIONS_STORAGE_ERROR", error?.message || "Operations retrieval failed.");
    }
  }

  async function listByTwin(storeName, twinId) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(tx.objectStore(storeName).index("twinId").getAll(twinId));
      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure("OPERATIONS_STORAGE_ERROR", error?.message || "Operations listing failed.");
    }
  }

  global.INFINICUS.DT.operationsStore = Object.freeze({ open, put, get, listByTwin });
})(window);

/* --- INFINICUS-DT-11-Operations-Process-Twin-Engine/src/engine/operations-process-twin-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function buildOperationsProcessState({
    operationsHandoffId,
    processInputs = [],
    stageInputs = [],
    resourceInputs = [],
    workItemInputs = []
  } = {}) {
    const handoff = await global.INFINICUS.DT
      .marketingAcquisitionTwinEngine
      .getOperationsHandoff({ operationsHandoffId });

    if (!handoff.ok) return handoff;

    const processes = [];
    for (const input of processInputs) {
      const built = global.INFINICUS.DT.processModel.createProcess({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      processes.push(built.data);
      await global.INFINICUS.DT.operationsStore.put("processes", built.data);
    }

    const stages = [];
    for (const input of stageInputs) {
      const built = global.INFINICUS.DT.processModel.createStage({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      stages.push(built.data);
    }

    const resources = [];
    for (const input of resourceInputs) {
      const built = global.INFINICUS.DT.resourceWorkItemModel.createResource({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      resources.push(built.data);
    }

    const workItems = [];
    for (const input of workItemInputs) {
      const built = global.INFINICUS.DT.resourceWorkItemModel.createWorkItem({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      workItems.push(built.data);
    }

    const validation = global.INFINICUS.DT.operationsValidator.validate({
      processes, stages, resources, workItems
    });

    if (!validation.valid) {
      return runtime.failure(
        "OPERATIONS_PROCESS_STATE_INVALID",
        "Operations and process validation failed.",
        validation
      );
    }

    for (const stage of stages) {
      await global.INFINICUS.DT.operationsStore.put("stages", stage);
    }
    for (const resource of resources) {
      await global.INFINICUS.DT.operationsStore.put("resources", resource);
    }
    for (const item of workItems) {
      await global.INFINICUS.DT.operationsStore.put("work_items", item);
    }

    const analysis = global.INFINICUS.DT.operationsAnalyzer.analyze({
      stages, resources, workItems
    });

    const snapshot = {
      operationsSnapshotId: runtime.createId("dt_operations_snapshot"),
      operationsHandoffId,
      businessId: handoff.data.businessId,
      twinId: handoff.data.twinId,
      processes: processes.map(runtime.clone),
      stages: stages.map(runtime.clone),
      resources: resources.map(runtime.clone),
      workItems: workItems.map(runtime.clone),
      analysis: runtime.clone(analysis),
      marketingAnalysis: runtime.clone(handoff.data.marketingAnalysis),
      salesAnalysis: runtime.clone(handoff.data.salesAnalysis),
      status: "current",
      createdAt: new Date().toISOString()
    };

    await global.INFINICUS.DT.operationsStore.put("snapshots", snapshot);

    const inventoryHandoff = {
      inventoryHandoffId: runtime.createId("dt_inventory_handoff"),
      targetBlock: "DT-12",
      operationsSnapshotId: snapshot.operationsSnapshotId,
      marketingSnapshotId: handoff.data.marketingSnapshotId,
      salesRevenueSnapshotId: handoff.data.salesRevenueSnapshotId,
      customerDemandSnapshotId: handoff.data.customerDemandSnapshotId,
      financialSnapshotId: handoff.data.financialSnapshotId,
      businessId: snapshot.businessId,
      twinId: snapshot.twinId,
      processes: processes.map(runtime.clone),
      stages: stages.map(runtime.clone),
      resources: resources.map(runtime.clone),
      workItems: workItems.map(runtime.clone),
      operationsAnalysis: runtime.clone(analysis),
      orders: handoff.data.orders.map(runtime.clone),
      customerProfiles: handoff.data.customerProfiles.map(runtime.clone),
      customerSegments: handoff.data.customerSegments.map(runtime.clone),
      financialProfile: runtime.clone(handoff.data.financialProfile),
      sourceContext: runtime.clone(handoff.data.sourceContext),
      correlationId: handoff.data.correlationId,
      status: "ready",
      createdAt: new Date().toISOString()
    };

    await global.INFINICUS.DT.operationsStore.put("inventory_handoffs", inventoryHandoff);

    await runtime.emit("dt.operations_process.completed", {
      operationsSnapshot: snapshot,
      inventoryHandoffId: inventoryHandoff.inventoryHandoffId
    });

    return runtime.success({ operationsSnapshot: snapshot, inventoryHandoff });
  }

  const api = Object.freeze({
    buildOperationsProcessState,
    getOperationsSnapshot: ({ operationsSnapshotId }) =>
      global.INFINICUS.DT.operationsStore.get("snapshots", operationsSnapshotId),
    getInventoryHandoff: ({ inventoryHandoffId }) =>
      global.INFINICUS.DT.operationsStore.get("inventory_handoffs", inventoryHandoffId),
    listTwinProcesses: ({ twinId }) =>
      global.INFINICUS.DT.operationsStore.listByTwin("processes", twinId),
    listTwinStages: ({ twinId }) =>
      global.INFINICUS.DT.operationsStore.listByTwin("stages", twinId),
    listTwinWorkItems: ({ twinId }) =>
      global.INFINICUS.DT.operationsStore.listByTwin("work_items", twinId)
  });

  runtime.registerService("dt.operations_process_twin", api, { block: "DT-11" });
  runtime.registerRoute("dt.operations_process.build", buildOperationsProcessState);
  global.INFINICUS.DT.operationsProcessTwinEngine = api;
})(window);

