/* --- INFINICUS-DT-12-Inventory-Supply-Network-Twin-Engine/src/model/inventory-state.js --- */
(function (global) {
  "use strict";

  function create(input = {}) {
    const runtime = global.INFINICUS.DT.runtime;
    if (!input.twinId || !input.productId || !input.inventoryLocationId || !input.period) {
      return runtime.failure("INVENTORY_STATE_INVALID", "twinId, productId, inventoryLocationId, and period are required.");
    }

    const onHand = Number(input.onHand || 0);
    const committed = Number(input.committed || 0);
    const inbound = Number(input.inbound || 0);
    const available = input.available == null ? onHand - committed : Number(input.available);

    return runtime.success({
      inventoryStateId: input.inventoryStateId || runtime.createId("dt_inventory_state"),
      twinId: String(input.twinId),
      productId: String(input.productId),
      inventoryLocationId: String(input.inventoryLocationId),
      period: String(input.period),
      onHand,
      committed,
      available,
      inbound,
      demandPerDay: Number(input.demandPerDay || 0),
      stockoutUnits: Number(input.stockoutUnits || 0),
      wasteUnits: Number(input.wasteUnits || 0),
      shrinkageUnits: Number(input.shrinkageUnits || 0),
      obsoleteUnits: Number(input.obsoleteUnits || 0),
      sourceType: String(input.sourceType || "observed"),
      lineage: runtime.clone(input.lineage || []),
      confidence: Number(input.confidence ?? 1),
      createdAt: new Date().toISOString()
    });
  }

  global.INFINICUS.DT.inventoryStateModel = Object.freeze({ create });
})(window);

/* --- INFINICUS-DT-12-Inventory-Supply-Network-Twin-Engine/src/analysis/inventory-supply-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze({ products = [], states = [], suppliers = [], purchaseOrders = [] } = {}) {
    const productById = new Map(products.map(item => [item.productId, item]));

    const totalOnHand = states.reduce((s,x)=>s+Number(x.onHand||0),0);
    const totalAvailable = states.reduce((s,x)=>s+Number(x.available||0),0);
    const totalDemandPerDay = states.reduce((s,x)=>s+Number(x.demandPerDay||0),0);
    const totalStockout = states.reduce((s,x)=>s+Number(x.stockoutUnits||0),0);
    const totalWaste = states.reduce((s,x)=>s+Number(x.wasteUnits||0),0);
    const totalShrinkage = states.reduce((s,x)=>s+Number(x.shrinkageUnits||0),0);
    const totalObsolete = states.reduce((s,x)=>s+Number(x.obsoleteUnits||0),0);

    const inventoryValue = states.reduce((sum, state) =>
      sum + Number(state.onHand || 0) * Number(productById.get(state.productId)?.unitCost || 0), 0);

    const daysOnHand = totalDemandPerDay === 0
      ? null
      : Number((totalOnHand / totalDemandPerDay).toFixed(4));

    const stockAvailabilityPercent = totalOnHand === 0
      ? null
      : Number((totalAvailable / totalOnHand * 100).toFixed(4));

    const stockoutRatePercent = totalDemandPerDay === 0
      ? null
      : Number((totalStockout / totalDemandPerDay * 100).toFixed(4));

    const supplierOnTimeDeliveryPercent = suppliers.length === 0
      ? null
      : Number((suppliers.reduce((s,x)=>s+Number(x.onTimeDeliveryPercent||0),0)/suppliers.length).toFixed(4));

    const averageSupplierLeadTimeDays = suppliers.length === 0
      ? null
      : Number((suppliers.reduce((s,x)=>s+Number(x.leadTimeDays||0),0)/suppliers.length).toFixed(4));

    const openPurchaseOrderCount = purchaseOrders.filter(po => po.status === "open").length;

    const reorderCandidates = states
      .filter(state => {
        const product = productById.get(state.productId);
        return product && Number(state.available) <= Number(product.reorderPoint || 0);
      })
      .map(state => ({
        productId: state.productId,
        inventoryLocationId: state.inventoryLocationId,
        available: state.available,
        reorderPoint: productById.get(state.productId).reorderPoint,
        reorderQuantity: productById.get(state.productId).reorderQuantity
      }));

    return {
      inventoryValue: Number(inventoryValue.toFixed(4)),
      totalOnHand: Number(totalOnHand.toFixed(4)),
      totalAvailable: Number(totalAvailable.toFixed(4)),
      daysOnHand,
      stockAvailabilityPercent,
      stockoutRatePercent,
      totalWaste: Number(totalWaste.toFixed(4)),
      totalShrinkage: Number(totalShrinkage.toFixed(4)),
      totalObsolete: Number(totalObsolete.toFixed(4)),
      supplierOnTimeDeliveryPercent,
      averageSupplierLeadTimeDays,
      openPurchaseOrderCount,
      reorderCandidates
    };
  }

  global.INFINICUS.DT.inventorySupplyAnalyzer = Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-12-Inventory-Supply-Network-Twin-Engine/src/validation/inventory-supply-validator.js --- */
(function (global) {
  "use strict";

  function validate({ products = [], locations = [], suppliers = [], purchaseOrders = [], states = [] } = {}) {
    const issues = [];
    const productIds = new Set(products.map(item => item.productId));
    const locationIds = new Set(locations.map(item => item.inventoryLocationId));
    const supplierIds = new Set(suppliers.map(item => item.supplierId));

    for (const state of states) {
      if (!productIds.has(state.productId)) issues.push(`Unknown product: ${state.productId}`);
      if (!locationIds.has(state.inventoryLocationId)) issues.push(`Unknown location: ${state.inventoryLocationId}`);
      if (state.confidence < 0 || state.confidence > 1) issues.push("Inventory-state confidence must be between 0 and 1.");
    }

    for (const po of purchaseOrders) {
      if (!supplierIds.has(po.supplierId)) issues.push(`Unknown supplier: ${po.supplierId}`);
      if (po.inventoryLocationId && !locationIds.has(po.inventoryLocationId)) issues.push(`Unknown PO location: ${po.inventoryLocationId}`);
      for (const line of po.lines || []) {
        if (!productIds.has(line.productId)) issues.push(`Unknown PO product: ${line.productId}`);
      }
    }

    return { valid: issues.length === 0, issues };
  }

  global.INFINICUS.DT.inventorySupplyValidator = Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-12-Inventory-Supply-Network-Twin-Engine/src/storage/inventory-supply-store.js --- */
(function (global) {
  "use strict";
  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_INVENTORY_SUPPLY";
  let dbPromise;
  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;
    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);
      req.onupgradeneeded = () => {
        const db = req.result;
        for (const [name, keyPath] of [
          ["products", "productId"],
          ["locations", "inventoryLocationId"],
          ["suppliers", "supplierId"],
          ["purchase_orders", "purchaseOrderId"],
          ["states", "inventoryStateId"],
          ["snapshots", "inventorySupplySnapshotId"],
          ["workforce_handoffs", "workforceHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            const store = db.createObjectStore(name, { keyPath });
            if (["products","locations","suppliers","purchase_orders","states"].includes(name)) {
              store.createIndex("twinId", "twinId", { unique: false });
            }
          }
        }
      };
      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });
    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(tx.objectStore(storeName).put(structuredClone(record)));
      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure("INVENTORY_STORAGE_ERROR", error?.message || "Inventory storage failed.");
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(tx.objectStore(storeName).get(id));
      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure("INVENTORY_RECORD_NOT_FOUND", "Inventory record was not found.", { storeName, id });
    } catch (error) {
      return runtime.failure("INVENTORY_STORAGE_ERROR", error?.message || "Inventory retrieval failed.");
    }
  }

  async function listByTwin(storeName, twinId) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(tx.objectStore(storeName).index("twinId").getAll(twinId));
      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure("INVENTORY_STORAGE_ERROR", error?.message || "Inventory listing failed.");
    }
  }

  global.INFINICUS.DT.inventorySupplyStore = Object.freeze({ open, put, get, listByTwin });
})(window);

/* --- INFINICUS-DT-12-Inventory-Supply-Network-Twin-Engine/src/engine/inventory-supply-twin-engine.js --- */
(function (global) {
  "use strict";
  const runtime = global.INFINICUS.DT.runtime;

  async function buildInventorySupplyState({
    inventoryHandoffId,
    productInputs = [],
    locationInputs = [],
    supplierInputs = [],
    purchaseOrderInputs = [],
    stateInputs = []
  } = {}) {
    const handoff = await global.INFINICUS.DT
      .operationsProcessTwinEngine
      .getInventoryHandoff({ inventoryHandoffId });

    if (!handoff.ok) return handoff;

    const products = [];
    for (const input of productInputs) {
      const built = global.INFINICUS.DT.productLocationModel.createProduct({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      products.push(built.data);
      await global.INFINICUS.DT.inventorySupplyStore.put("products", built.data);
    }

    const locations = [];
    for (const input of locationInputs) {
      const built = global.INFINICUS.DT.productLocationModel.createLocation({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      locations.push(built.data);
      await global.INFINICUS.DT.inventorySupplyStore.put("locations", built.data);
    }

    const suppliers = [];
    for (const input of supplierInputs) {
      const built = global.INFINICUS.DT.supplierPurchaseOrderModel.createSupplier({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      suppliers.push(built.data);
      await global.INFINICUS.DT.inventorySupplyStore.put("suppliers", built.data);
    }

    const purchaseOrders = [];
    for (const input of purchaseOrderInputs) {
      const built = global.INFINICUS.DT.supplierPurchaseOrderModel.createPurchaseOrder({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      purchaseOrders.push(built.data);
    }

    const states = [];
    for (const input of stateInputs) {
      const built = global.INFINICUS.DT.inventoryStateModel.create({
        ...input,
        twinId: handoff.data.twinId
      });
      if (!built.ok) return built;
      states.push(built.data);
    }

    const validation = global.INFINICUS.DT.inventorySupplyValidator.validate({
      products, locations, suppliers, purchaseOrders, states
    });

    if (!validation.valid) {
      return runtime.failure(
        "INVENTORY_SUPPLY_STATE_INVALID",
        "Inventory and supply validation failed.",
        validation
      );
    }

    for (const po of purchaseOrders) {
      await global.INFINICUS.DT.inventorySupplyStore.put("purchase_orders", po);
    }
    for (const state of states) {
      await global.INFINICUS.DT.inventorySupplyStore.put("states", state);
    }

    const analysis = global.INFINICUS.DT.inventorySupplyAnalyzer.analyze({
      products, states, suppliers, purchaseOrders
    });

    const snapshot = {
      inventorySupplySnapshotId: runtime.createId("dt_inventory_supply_snapshot"),
      inventoryHandoffId,
      businessId: handoff.data.businessId,
      twinId: handoff.data.twinId,
      products: products.map(runtime.clone),
      locations: locations.map(runtime.clone),
      suppliers: suppliers.map(runtime.clone),
      purchaseOrders: purchaseOrders.map(runtime.clone),
      states: states.map(runtime.clone),
      analysis: runtime.clone(analysis),
      operationsAnalysis: runtime.clone(handoff.data.operationsAnalysis),
      status: "current",
      createdAt: new Date().toISOString()
    };

    await global.INFINICUS.DT.inventorySupplyStore.put("snapshots", snapshot);

    const workforceHandoff = {
      workforceHandoffId: runtime.createId("dt_workforce_handoff"),
      targetBlock: "DT-13",
      inventorySupplySnapshotId: snapshot.inventorySupplySnapshotId,
      operationsSnapshotId: handoff.data.operationsSnapshotId,
      marketingSnapshotId: handoff.data.marketingSnapshotId,
      salesRevenueSnapshotId: handoff.data.salesRevenueSnapshotId,
      customerDemandSnapshotId: handoff.data.customerDemandSnapshotId,
      financialSnapshotId: handoff.data.financialSnapshotId,
      businessId: snapshot.businessId,
      twinId: snapshot.twinId,
      inventoryAnalysis: runtime.clone(analysis),
      products: products.map(runtime.clone),
      locations: locations.map(runtime.clone),
      suppliers: suppliers.map(runtime.clone),
      purchaseOrders: purchaseOrders.map(runtime.clone),
      inventoryStates: states.map(runtime.clone),
      processes: handoff.data.processes.map(runtime.clone),
      stages: handoff.data.stages.map(runtime.clone),
      resources: handoff.data.resources.map(runtime.clone),
      workItems: handoff.data.workItems.map(runtime.clone),
      operationsAnalysis: runtime.clone(handoff.data.operationsAnalysis),
      customerProfiles: handoff.data.customerProfiles.map(runtime.clone),
      customerSegments: handoff.data.customerSegments.map(runtime.clone),
      financialProfile: runtime.clone(handoff.data.financialProfile),
      sourceContext: runtime.clone(handoff.data.sourceContext),
      correlationId: handoff.data.correlationId,
      status: "ready",
      createdAt: new Date().toISOString()
    };

    await global.INFINICUS.DT.inventorySupplyStore.put("workforce_handoffs", workforceHandoff);

    await runtime.emit("dt.inventory_supply.completed", {
      inventorySupplySnapshot: snapshot,
      workforceHandoffId: workforceHandoff.workforceHandoffId
    });

    return runtime.success({ inventorySupplySnapshot: snapshot, workforceHandoff });
  }

  const api = Object.freeze({
    buildInventorySupplyState,
    getInventorySupplySnapshot: ({ inventorySupplySnapshotId }) =>
      global.INFINICUS.DT.inventorySupplyStore.get("snapshots", inventorySupplySnapshotId),
    getWorkforceHandoff: ({ workforceHandoffId }) =>
      global.INFINICUS.DT.inventorySupplyStore.get("workforce_handoffs", workforceHandoffId),
    listTwinProducts: ({ twinId }) =>
      global.INFINICUS.DT.inventorySupplyStore.listByTwin("products", twinId),
    listTwinSuppliers: ({ twinId }) =>
      global.INFINICUS.DT.inventorySupplyStore.listByTwin("suppliers", twinId),
    listTwinInventoryStates: ({ twinId }) =>
      global.INFINICUS.DT.inventorySupplyStore.listByTwin("states", twinId)
  });

  runtime.registerService("dt.inventory_supply_twin", api, { block: "DT-12" });
  runtime.registerRoute("dt.inventory_supply.build", buildInventorySupplyState);
  global.INFINICUS.DT.inventorySupplyTwinEngine = api;
})(window);

