/* --- INFINICUS-DT-13-Workforce-Capability-Twin-Engine/src/analysis/workforce-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze({
    members = [],
    capabilities = [],
    states = [],
    positions = []
  } = {}) {
    const totalAvailableHours =
      states.reduce(
        (sum, state) =>
          sum + Number(state.availableHours || 0),
        0
      );

    const totalAssignedHours =
      states.reduce(
        (sum, state) =>
          sum + Number(state.assignedHours || 0),
        0
      );

    const totalProductiveHours =
      states.reduce(
        (sum, state) =>
          sum + Number(state.productiveHours || 0),
        0
      );

    const totalAbsenceHours =
      states.reduce(
        (sum, state) =>
          sum + Number(state.absenceHours || 0),
        0
      );

    const utilizationPercent =
      totalAvailableHours === 0
        ? null
        : Number(
            (
              totalAssignedHours /
              totalAvailableHours *
              100
            ).toFixed(4)
          );

    const productivityPercent =
      totalAssignedHours === 0
        ? null
        : Number(
            (
              totalProductiveHours /
              totalAssignedHours *
              100
            ).toFixed(4)
          );

    const absenceRatePercent =
      totalAvailableHours === 0
        ? null
        : Number(
            (
              totalAbsenceHours /
              totalAvailableHours *
              100
            ).toFixed(4)
          );

    const vacantPositions =
      positions.filter(position =>
        !position.occupantEntityInstanceId ||
        position.status === "vacant"
      );

    const capabilityCoverage =
      new Map();

    for (const capability of capabilities) {
      if (!capabilityCoverage.has(capability.skillId)) {
        capabilityCoverage.set(
          capability.skillId,
          {
            skillId:
              capability.skillId,
            memberCount: 0,
            verifiedCount: 0,
            averageProficiencyScore: 0,
            totalProficiencyScore: 0
          }
        );
      }

      const record =
        capabilityCoverage.get(capability.skillId);

      record.memberCount += 1;
      record.verifiedCount +=
        capability.verified ? 1 : 0;
      record.totalProficiencyScore +=
        Number(capability.proficiencyScore || 0);
    }

    const skillCoverage =
      [...capabilityCoverage.values()]
        .map(record => ({
          skillId:
            record.skillId,
          memberCount:
            record.memberCount,
          verifiedCount:
            record.verifiedCount,
          averageProficiencyScore:
            record.memberCount === 0
              ? 0
              : Number(
                  (
                    record.totalProficiencyScore /
                    record.memberCount
                  ).toFixed(4)
                )
        }))
        .sort((a, b) =>
          a.memberCount - b.memberCount
        );

    const overloadedMembers =
      states
        .filter(state =>
          state.availableHours > 0 &&
          state.assignedHours /
            state.availableHours >
            1
        )
        .map(state => ({
          workforceMemberId:
            state.workforceMemberId,
          utilizationPercent:
            Number(
              (
                state.assignedHours /
                state.availableHours *
                100
              ).toFixed(4)
            )
        }));

    return {
      headcount:
        members.filter(member =>
          member.status === "active"
        ).length,
      positionCount:
        positions.length,
      vacantPositionCount:
        vacantPositions.length,
      totalAvailableHours:
        Number(totalAvailableHours.toFixed(4)),
      totalAssignedHours:
        Number(totalAssignedHours.toFixed(4)),
      totalProductiveHours:
        Number(totalProductiveHours.toFixed(4)),
      utilizationPercent,
      productivityPercent,
      absenceRatePercent,
      skillCoverage,
      overloadedMembers
    };
  }

  global.INFINICUS.DT.workforceAnalyzer =
    Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-13-Workforce-Capability-Twin-Engine/src/validation/workforce-validator.js --- */
(function (global) {
  "use strict";

  function validate({
    members = [],
    skills = [],
    capabilities = [],
    states = [],
    positions = []
  } = {}) {
    const issues = [];

    const memberIds =
      new Set(
        members.map(item =>
          item.workforceMemberId
        )
      );

    const skillIds =
      new Set(
        skills.map(item =>
          item.skillId
        )
      );

    const positionIds =
      new Set(
        positions.map(item =>
          item.positionId
        )
      );

    for (const member of members) {
      if (
        member.positionId &&
        !positionIds.has(member.positionId)
      ) {
        issues.push(
          `Unknown workforce position: ${member.positionId}`
        );
      }

      if (
        member.confidence < 0 ||
        member.confidence > 1
      ) {
        issues.push(
          "Workforce-member confidence must be between 0 and 1."
        );
      }
    }

    for (const capability of capabilities) {
      if (
        !memberIds.has(
          capability.workforceMemberId
        )
      ) {
        issues.push(
          `Unknown workforce member: ${capability.workforceMemberId}`
        );
      }

      if (!skillIds.has(capability.skillId)) {
        issues.push(
          `Unknown skill: ${capability.skillId}`
        );
      }
    }

    for (const state of states) {
      if (
        !memberIds.has(state.workforceMemberId)
      ) {
        issues.push(
          `Unknown workforce state member: ${state.workforceMemberId}`
        );
      }

      if (
        state.confidence < 0 ||
        state.confidence > 1
      ) {
        issues.push(
          "Workforce-state confidence must be between 0 and 1."
        );
      }
    }

    return {
      valid:
        issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.workforceValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-13-Workforce-Capability-Twin-Engine/src/storage/workforce-store.js --- */
(function (global) {
  "use strict";

  const runtime =
    global.INFINICUS.DT.runtime;

  const DB_NAME =
    "INFINICUS_DT_WORKFORCE_CAPABILITY";

  let dbPromise;

  const request = req =>
    new Promise((resolve, reject) => {
      req.onsuccess = () =>
        resolve(req.result);
      req.onerror = () =>
        reject(req.error);
    });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise =
      new Promise((resolve, reject) => {
        const req =
          indexedDB.open(DB_NAME, 1);

        req.onupgradeneeded = () => {
          const db = req.result;

          for (const [name, keyPath] of [
            ["members", "workforceMemberId"],
            ["skills", "skillId"],
            ["capabilities", "capabilityId"],
            ["states", "workforceStateId"],
            ["snapshots", "workforceSnapshotId"],
            ["asset_handoffs", "assetHandoffId"]
          ]) {
            if (
              !db.objectStoreNames
                .contains(name)
            ) {
              const store =
                db.createObjectStore(
                  name,
                  { keyPath }
                );

              if (
                [
                  "members",
                  "skills",
                  "capabilities",
                  "states"
                ].includes(name)
              ) {
                store.createIndex(
                  "twinId",
                  "twinId",
                  { unique: false }
                );
              }
            }
          }
        };

        req.onsuccess = () =>
          resolve(req.result);

        req.onerror = () =>
          reject(req.error);
      });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx =
        db.transaction(
          storeName,
          "readwrite"
        );

      await request(
        tx.objectStore(storeName)
          .put(structuredClone(record))
      );

      return runtime.success(
        structuredClone(record)
      );
    } catch (error) {
      return runtime.failure(
        "WORKFORCE_STORAGE_ERROR",
        error?.message ||
          "Workforce storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx =
        db.transaction(
          storeName,
          "readonly"
        );

      const value =
        await request(
          tx.objectStore(storeName)
            .get(id)
        );

      return value
        ? runtime.success(
            structuredClone(value)
          )
        : runtime.failure(
            "WORKFORCE_RECORD_NOT_FOUND",
            "Workforce record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "WORKFORCE_STORAGE_ERROR",
        error?.message ||
          "Workforce retrieval failed."
      );
    }
  }

  async function listByTwin(
    storeName,
    twinId
  ) {
    try {
      const db = await open();
      const tx =
        db.transaction(
          storeName,
          "readonly"
        );

      const values =
        await request(
          tx.objectStore(storeName)
            .index("twinId")
            .getAll(twinId)
        );

      return runtime.success(
        values.map(structuredClone)
      );
    } catch (error) {
      return runtime.failure(
        "WORKFORCE_STORAGE_ERROR",
        error?.message ||
          "Workforce listing failed."
      );
    }
  }

  global.INFINICUS.DT.workforceStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-13-Workforce-Capability-Twin-Engine/src/engine/workforce-capability-twin-engine.js --- */
(function (global) {
  "use strict";

  const runtime =
    global.INFINICUS.DT.runtime;

  async function buildWorkforceCapabilityState({
    workforceHandoffId,
    memberInputs = [],
    skillInputs = [],
    capabilityInputs = [],
    stateInputs = [],
    positionInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .inventorySupplyTwinEngine
        .getWorkforceHandoff({
          workforceHandoffId
        });

    if (!handoff.ok) return handoff;

    const positions =
      positionInputs.length
        ? positionInputs
        : handoff.data.sourceContext
            ?.organizationContext
            ?.positions || [];

    const members = [];

    for (const input of memberInputs) {
      const built =
        global.INFINICUS.DT
          .workforceMemberModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      members.push(built.data);

      await global.INFINICUS.DT
        .workforceStore
        .put("members", built.data);
    }

    const skills = [];

    for (const input of skillInputs) {
      const built =
        global.INFINICUS.DT
          .capabilitySkillModel
          .createSkill({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      skills.push(built.data);

      await global.INFINICUS.DT
        .workforceStore
        .put("skills", built.data);
    }

    const capabilities = [];

    for (const input of capabilityInputs) {
      const built =
        global.INFINICUS.DT
          .capabilitySkillModel
          .createCapability({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      capabilities.push(built.data);
    }

    const states = [];

    for (const input of stateInputs) {
      const built =
        global.INFINICUS.DT
          .workforceStateModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      states.push(built.data);
    }

    const validation =
      global.INFINICUS.DT
        .workforceValidator
        .validate({
          members,
          skills,
          capabilities,
          states,
          positions
        });

    if (!validation.valid) {
      return runtime.failure(
        "WORKFORCE_CAPABILITY_STATE_INVALID",
        "Workforce and capability validation failed.",
        validation
      );
    }

    for (const capability of capabilities) {
      await global.INFINICUS.DT
        .workforceStore
        .put(
          "capabilities",
          capability
        );
    }

    for (const state of states) {
      await global.INFINICUS.DT
        .workforceStore
        .put("states", state);
    }

    const analysis =
      global.INFINICUS.DT
        .workforceAnalyzer
        .analyze({
          members,
          capabilities,
          states,
          positions
        });

    const snapshot = {
      workforceSnapshotId:
        runtime.createId(
          "dt_workforce_snapshot"
        ),
      workforceHandoffId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      members:
        members.map(runtime.clone),
      skills:
        skills.map(runtime.clone),
      capabilities:
        capabilities.map(runtime.clone),
      states:
        states.map(runtime.clone),
      positions:
        positions.map(runtime.clone),
      analysis:
        runtime.clone(analysis),
      inventoryAnalysis:
        runtime.clone(
          handoff.data.inventoryAnalysis
        ),
      operationsAnalysis:
        runtime.clone(
          handoff.data.operationsAnalysis
        ),
      status: "current",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .workforceStore
      .put("snapshots", snapshot);

    const assetHandoff = {
      assetHandoffId:
        runtime.createId("dt_asset_handoff"),
      targetBlock: "DT-14",
      workforceSnapshotId:
        snapshot.workforceSnapshotId,
      inventorySupplySnapshotId:
        handoff.data.inventorySupplySnapshotId,
      operationsSnapshotId:
        handoff.data.operationsSnapshotId,
      businessId:
        snapshot.businessId,
      twinId:
        snapshot.twinId,
      workforceAnalysis:
        runtime.clone(analysis),
      workforceMembers:
        members.map(runtime.clone),
      skills:
        skills.map(runtime.clone),
      capabilities:
        capabilities.map(runtime.clone),
      workforceStates:
        states.map(runtime.clone),
      products:
        handoff.data.products.map(runtime.clone),
      locations:
        handoff.data.locations.map(runtime.clone),
      suppliers:
        handoff.data.suppliers.map(runtime.clone),
      processes:
        handoff.data.processes.map(runtime.clone),
      resources:
        handoff.data.resources.map(runtime.clone),
      sourceContext:
        runtime.clone(
          handoff.data.sourceContext
        ),
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .workforceStore
      .put(
        "asset_handoffs",
        assetHandoff
      );

    await runtime.emit(
      "dt.workforce_capability.completed",
      {
        workforceSnapshot:
          snapshot,
        assetHandoffId:
          assetHandoff.assetHandoffId
      }
    );

    return runtime.success({
      workforceSnapshot:
        snapshot,
      assetHandoff
    });
  }

  const api = Object.freeze({
    buildWorkforceCapabilityState,
    getWorkforceSnapshot: ({
      workforceSnapshotId
    }) =>
      global.INFINICUS.DT
        .workforceStore
        .get(
          "snapshots",
          workforceSnapshotId
        ),
    getAssetHandoff: ({
      assetHandoffId
    }) =>
      global.INFINICUS.DT
        .workforceStore
        .get(
          "asset_handoffs",
          assetHandoffId
        ),
    listTwinMembers: ({ twinId }) =>
      global.INFINICUS.DT
        .workforceStore
        .listByTwin(
          "members",
          twinId
        ),
    listTwinSkills: ({ twinId }) =>
      global.INFINICUS.DT
        .workforceStore
        .listByTwin(
          "skills",
          twinId
        ),
    listTwinWorkforceStates: ({
      twinId
    }) =>
      global.INFINICUS.DT
        .workforceStore
        .listByTwin(
          "states",
          twinId
        )
  });

  runtime.registerService(
    "dt.workforce_capability_twin",
    api,
    { block: "DT-13" }
  );

  runtime.registerRoute(
    "dt.workforce_capability.build",
    buildWorkforceCapabilityState
  );

  global.INFINICUS.DT
    .workforceCapabilityTwinEngine = api;
})(window);

