/* --- INFINICUS-DT-14-Asset-Facility-Infrastructure-Twin-Engine/src/analysis/asset-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze({
    assets = [],
    states = [],
    dependencies = []
  } = {}) {
    const stateByAsset =
      new Map();

    for (const state of states) {
      stateByAsset.set(
        state.assetId,
        state
      );
    }

    const average = field => {
      const values =
        states
          .map(state =>
            Number(state[field])
          )
          .filter(Number.isFinite);

      return values.length
        ? Number(
            (
              values.reduce(
                (a, b) => a + b,
                0
              ) / values.length
            ).toFixed(4)
          )
        : null;
    };

    const criticalAssets =
      assets.filter(asset =>
        ["high", "critical"]
          .includes(asset.criticality)
      );

    const maintenanceDue =
      states.filter(state =>
        state.maintenanceDue
      );

    const degradedAssets =
      assets
        .filter(asset => {
          const state =
            stateByAsset.get(asset.assetId);

          return state &&
            (
              state.conditionScore < 60 ||
              state.availabilityPercent < 80
            );
        })
        .map(asset => ({
          assetId:
            asset.assetId,
          name:
            asset.name,
          state:
            structuredClone(
              stateByAsset.get(asset.assetId)
            )
        }));

    const singlePointsOfFailure =
      dependencies
        .filter(dependency =>
          dependency.critical &&
          dependency.redundancyAssetIds.length === 0
        )
        .map(structuredClone);

    const totalAcquisitionValue =
      assets.reduce(
        (sum, asset) =>
          sum +
          Number(
            asset.acquisitionValue || 0
          ),
        0
      );

    return {
      assetCount:
        assets.length,
      criticalAssetCount:
        criticalAssets.length,
      maintenanceDueCount:
        maintenanceDue.length,
      averageConditionScore:
        average("conditionScore"),
      averageAvailabilityPercent:
        average("availabilityPercent"),
      averageUtilizationPercent:
        average("utilizationPercent"),
      totalDowntimeHours:
        Number(
          states.reduce(
            (sum, state) =>
              sum +
              Number(
                state.downtimeHours || 0
              ),
            0
          ).toFixed(4)
        ),
      totalFailureCount:
        states.reduce(
          (sum, state) =>
            sum +
            Number(
              state.failureCount || 0
            ),
          0
        ),
      totalAcquisitionValue:
        Number(
          totalAcquisitionValue.toFixed(4)
        ),
      degradedAssets,
      singlePointsOfFailure
    };
  }

  global.INFINICUS.DT.assetAnalyzer =
    Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-14-Asset-Facility-Infrastructure-Twin-Engine/src/validation/asset-validator.js --- */
(function (global) {
  "use strict";

  function validate({
    assets = [],
    facilities = [],
    states = [],
    dependencies = [],
    workforceMembers = []
  } = {}) {
    const issues = [];

    const assetIds =
      new Set(
        assets.map(item => item.assetId)
      );

    const facilityIds =
      new Set(
        facilities.map(
          item => item.facilityId
        )
      );

    const workforceIds =
      new Set(
        workforceMembers.map(
          item =>
            item.workforceMemberId
        )
      );

    for (const asset of assets) {
      if (
        asset.facilityId &&
        !facilityIds.has(
          asset.facilityId
        )
      ) {
        issues.push(
          `Unknown facility: ${asset.facilityId}`
        );
      }

      if (
        asset.assignedWorkforceMemberId &&
        !workforceIds.has(
          asset.assignedWorkforceMemberId
        )
      ) {
        issues.push(
          `Unknown assigned workforce member: ${asset.assignedWorkforceMemberId}`
        );
      }
    }

    for (const state of states) {
      if (!assetIds.has(state.assetId)) {
        issues.push(
          `Unknown asset state reference: ${state.assetId}`
        );
      }

      if (
        state.confidence < 0 ||
        state.confidence > 1
      ) {
        issues.push(
          "Asset-state confidence must be between 0 and 1."
        );
      }
    }

    for (const dependency of dependencies) {
      if (
        !assetIds.has(
          dependency.sourceAssetId
        )
      ) {
        issues.push(
          `Unknown dependency source: ${dependency.sourceAssetId}`
        );
      }

      if (
        !assetIds.has(
          dependency.targetAssetId
        )
      ) {
        issues.push(
          `Unknown dependency target: ${dependency.targetAssetId}`
        );
      }

      if (
        dependency.sourceAssetId ===
        dependency.targetAssetId
      ) {
        issues.push(
          "An asset cannot depend on itself."
        );
      }

      for (
        const redundancyAssetId
        of dependency.redundancyAssetIds
      ) {
        if (
          !assetIds.has(
            redundancyAssetId
          )
        ) {
          issues.push(
            `Unknown redundancy asset: ${redundancyAssetId}`
          );
        }
      }
    }

    return {
      valid:
        issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT.assetValidator =
    Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-14-Asset-Facility-Infrastructure-Twin-Engine/src/storage/asset-store.js --- */
(function (global) {
  "use strict";

  const runtime =
    global.INFINICUS.DT.runtime;

  const DB_NAME =
    "INFINICUS_DT_ASSET_INFRASTRUCTURE";

  let dbPromise;

  const request = req =>
    new Promise((resolve, reject) => {
      req.onsuccess = () =>
        resolve(req.result);
      req.onerror = () =>
        reject(req.error);
    });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise =
      new Promise((resolve, reject) => {
        const req =
          indexedDB.open(DB_NAME, 1);

        req.onupgradeneeded = () => {
          const db = req.result;

          for (const [name, keyPath] of [
            ["assets", "assetId"],
            ["facilities", "facilityId"],
            ["states", "assetStateId"],
            ["dependencies", "assetDependencyId"],
            ["snapshots", "assetSnapshotId"],
            ["market_handoffs", "marketHandoffId"]
          ]) {
            if (
              !db.objectStoreNames
                .contains(name)
            ) {
              const store =
                db.createObjectStore(
                  name,
                  { keyPath }
                );

              if (
                [
                  "assets",
                  "facilities",
                  "states",
                  "dependencies"
                ].includes(name)
              ) {
                store.createIndex(
                  "twinId",
                  "twinId",
                  { unique: false }
                );
              }
            }
          }
        };

        req.onsuccess = () =>
          resolve(req.result);

        req.onerror = () =>
          reject(req.error);
      });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();

      const tx =
        db.transaction(
          storeName,
          "readwrite"
        );

      await request(
        tx.objectStore(storeName)
          .put(structuredClone(record))
      );

      return runtime.success(
        structuredClone(record)
      );
    } catch (error) {
      return runtime.failure(
        "ASSET_STORAGE_ERROR",
        error?.message ||
          "Asset storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();

      const tx =
        db.transaction(
          storeName,
          "readonly"
        );

      const value =
        await request(
          tx.objectStore(storeName)
            .get(id)
        );

      return value
        ? runtime.success(
            structuredClone(value)
          )
        : runtime.failure(
            "ASSET_RECORD_NOT_FOUND",
            "Asset record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "ASSET_STORAGE_ERROR",
        error?.message ||
          "Asset retrieval failed."
      );
    }
  }

  async function listByTwin(
    storeName,
    twinId
  ) {
    try {
      const db = await open();

      const tx =
        db.transaction(
          storeName,
          "readonly"
        );

      const values =
        await request(
          tx.objectStore(storeName)
            .index("twinId")
            .getAll(twinId)
        );

      return runtime.success(
        values.map(structuredClone)
      );
    } catch (error) {
      return runtime.failure(
        "ASSET_STORAGE_ERROR",
        error?.message ||
          "Asset listing failed."
      );
    }
  }

  global.INFINICUS.DT.assetStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-14-Asset-Facility-Infrastructure-Twin-Engine/src/engine/asset-infrastructure-twin-engine.js --- */
(function (global) {
  "use strict";

  const runtime =
    global.INFINICUS.DT.runtime;

  async function buildAssetInfrastructureState({
    assetHandoffId,
    facilityInputs = [],
    assetInputs = [],
    stateInputs = [],
    dependencyInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .workforceCapabilityTwinEngine
        .getAssetHandoff({
          assetHandoffId
        });

    if (!handoff.ok) return handoff;

    const facilities = [];

    for (const input of facilityInputs) {
      const built =
        global.INFINICUS.DT
          .facilityModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      facilities.push(built.data);

      await global.INFINICUS.DT
        .assetStore
        .put(
          "facilities",
          built.data
        );
    }

    const assets = [];

    for (const input of assetInputs) {
      const built =
        global.INFINICUS.DT
          .assetModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      assets.push(built.data);
    }

    const states = [];

    for (const input of stateInputs) {
      const built =
        global.INFINICUS.DT
          .assetStateDependencyModel
          .createState({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      states.push(built.data);
    }

    const dependencies = [];

    for (const input of dependencyInputs) {
      const built =
        global.INFINICUS.DT
          .assetStateDependencyModel
          .createDependency({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      dependencies.push(built.data);
    }

    const validation =
      global.INFINICUS.DT
        .assetValidator
        .validate({
          assets,
          facilities,
          states,
          dependencies,
          workforceMembers:
            handoff.data.workforceMembers
        });

    if (!validation.valid) {
      return runtime.failure(
        "ASSET_INFRASTRUCTURE_STATE_INVALID",
        "Asset and infrastructure validation failed.",
        validation
      );
    }

    for (const asset of assets) {
      await global.INFINICUS.DT
        .assetStore
        .put("assets", asset);
    }

    for (const state of states) {
      await global.INFINICUS.DT
        .assetStore
        .put("states", state);
    }

    for (
      const dependency
      of dependencies
    ) {
      await global.INFINICUS.DT
        .assetStore
        .put(
          "dependencies",
          dependency
        );
    }

    const analysis =
      global.INFINICUS.DT
        .assetAnalyzer
        .analyze({
          assets,
          states,
          dependencies
        });

    const snapshot = {
      assetSnapshotId:
        runtime.createId(
          "dt_asset_snapshot"
        ),
      assetHandoffId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      facilities:
        facilities.map(runtime.clone),
      assets:
        assets.map(runtime.clone),
      states:
        states.map(runtime.clone),
      dependencies:
        dependencies.map(runtime.clone),
      analysis:
        runtime.clone(analysis),
      workforceAnalysis:
        runtime.clone(
          handoff.data.workforceAnalysis
        ),
      status: "current",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .assetStore
      .put("snapshots", snapshot);

    const marketHandoff = {
      marketHandoffId:
        runtime.createId("dt_market_handoff"),
      targetBlock: "DT-15",
      assetSnapshotId:
        snapshot.assetSnapshotId,
      workforceSnapshotId:
        handoff.data.workforceSnapshotId,
      inventorySupplySnapshotId:
        handoff.data.inventorySupplySnapshotId,
      operationsSnapshotId:
        handoff.data.operationsSnapshotId,
      businessId:
        snapshot.businessId,
      twinId:
        snapshot.twinId,
      assetAnalysis:
        runtime.clone(analysis),
      facilities:
        facilities.map(runtime.clone),
      assets:
        assets.map(runtime.clone),
      assetStates:
        states.map(runtime.clone),
      assetDependencies:
        dependencies.map(runtime.clone),
      workforceAnalysis:
        runtime.clone(
          handoff.data.workforceAnalysis
        ),
      workforceMembers:
        handoff.data.workforceMembers
          .map(runtime.clone),
      products:
        handoff.data.products
          .map(runtime.clone),
      locations:
        handoff.data.locations
          .map(runtime.clone),
      suppliers:
        handoff.data.suppliers
          .map(runtime.clone),
      processes:
        handoff.data.processes
          .map(runtime.clone),
      resources:
        handoff.data.resources
          .map(runtime.clone),
      sourceContext:
        runtime.clone(
          handoff.data.sourceContext
        ),
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .assetStore
      .put(
        "market_handoffs",
        marketHandoff
      );

    await runtime.emit(
      "dt.asset_infrastructure.completed",
      {
        assetSnapshot:
          snapshot,
        marketHandoffId:
          marketHandoff.marketHandoffId
      }
    );

    return runtime.success({
      assetSnapshot:
        snapshot,
      marketHandoff
    });
  }

  const api = Object.freeze({
    buildAssetInfrastructureState,
    getAssetSnapshot: ({
      assetSnapshotId
    }) =>
      global.INFINICUS.DT
        .assetStore
        .get(
          "snapshots",
          assetSnapshotId
        ),
    getMarketHandoff: ({
      marketHandoffId
    }) =>
      global.INFINICUS.DT
        .assetStore
        .get(
          "market_handoffs",
          marketHandoffId
        ),
    listTwinAssets: ({ twinId }) =>
      global.INFINICUS.DT
        .assetStore
        .listByTwin(
          "assets",
          twinId
        ),
    listTwinFacilities: ({ twinId }) =>
      global.INFINICUS.DT
        .assetStore
        .listByTwin(
          "facilities",
          twinId
        ),
    listTwinAssetStates: ({ twinId }) =>
      global.INFINICUS.DT
        .assetStore
        .listByTwin(
          "states",
          twinId
        )
  });

  runtime.registerService(
    "dt.asset_infrastructure_twin",
    api,
    { block: "DT-14" }
  );

  runtime.registerRoute(
    "dt.asset_infrastructure.build",
    buildAssetInfrastructureState
  );

  global.INFINICUS.DT
    .assetInfrastructureTwinEngine = api;
})(window);

