/* --- INFINICUS-DT-16-Business-State-Synchronization-Engine/src/model/synchronization-policy.js --- */
(function (global) {
  "use strict";

  function create(input = {}) {
    const runtime =
      global.INFINICUS.DT.runtime;

    return runtime.success({
      synchronizationPolicyId:
        input.synchronizationPolicyId ||
        runtime.createId(
          "dt_sync_policy"
        ),
      name:
        String(
          input.name ||
          "Default synchronization policy"
        ),
      sourcePriority:
        runtime.clone(
          input.sourcePriority || [
            "observed",
            "calculated",
            "inferred",
            "assumed"
          ]
        ),
      minimumConfidence:
        Math.max(
          0,
          Math.min(
            1,
            Number(
              input.minimumConfidence ?? 0.5
            )
          )
        ),
      maximumAgeMinutes:
        Math.max(
          1,
          Number(
            input.maximumAgeMinutes || 1440
          )
        ),
      conflictTolerance:
        Math.max(
          0,
          Number(
            input.conflictTolerance || 0
          )
        ),
      rejectSimulatedState:
        input.rejectSimulatedState !== false,
      status:
        String(input.status || "active"),
      createdAt:
        new Date().toISOString()
    });
  }

  global.INFINICUS.DT
    .synchronizationPolicyModel =
      Object.freeze({ create });
})(window);

/* --- INFINICUS-DT-16-Business-State-Synchronization-Engine/src/sync/state-normalizer.js --- */
(function (global) {
  "use strict";

  function flattenDomain(
    domain,
    value,
    prefix = ""
  ) {
    const results = [];

    if (
      value == null ||
      typeof value !== "object" ||
      Array.isArray(value)
    ) {
      results.push({
        stateKey:
          [domain, prefix]
            .filter(Boolean)
            .join("."),
        value:
          structuredClone(value),
        sourceType:
          "observed",
        confidence:
          1,
        observedAt:
          new Date().toISOString(),
        lineage: []
      });

      return results;
    }

    for (
      const [key, child]
      of Object.entries(value)
    ) {
      const nextPrefix =
        prefix
          ? `${prefix}.${key}`
          : key;

      if (
        child &&
        typeof child === "object" &&
        !Array.isArray(child) &&
        !(
          "value" in child &&
          (
            "sourceType" in child ||
            "confidence" in child ||
            "lineage" in child
          )
        )
      ) {
        results.push(
          ...flattenDomain(
            domain,
            child,
            nextPrefix
          )
        );
      } else {
        const wrapped =
          child &&
          typeof child === "object" &&
          !Array.isArray(child) &&
          "value" in child;

        results.push({
          stateKey:
            `${domain}.${nextPrefix}`,
          value:
            structuredClone(
              wrapped
                ? child.value
                : child
            ),
          sourceType:
            wrapped
              ? String(
                  child.sourceType ||
                  "observed"
                )
              : "observed",
          confidence:
            wrapped
              ? Number(
                  child.confidence ?? 1
                )
              : 1,
          observedAt:
            wrapped
              ? (
                  child.observedAt ||
                  new Date().toISOString()
                )
              : new Date().toISOString(),
          lineage:
            wrapped
              ? structuredClone(
                  child.lineage || []
                )
              : []
        });
      }
    }

    return results;
  }

  global.INFINICUS.DT
    .stateNormalizer =
      Object.freeze({
        flattenDomain
      });
})(window);

/* --- INFINICUS-DT-16-Business-State-Synchronization-Engine/src/sync/conflict-detector.js --- */
(function (global) {
  "use strict";

  function equivalent(
    left,
    right,
    tolerance = 0
  ) {
    if (
      Number.isFinite(Number(left)) &&
      Number.isFinite(Number(right))
    ) {
      return Math.abs(
        Number(left) -
        Number(right)
      ) <= tolerance;
    }

    return JSON.stringify(left) ===
      JSON.stringify(right);
  }

  function detect({
    current,
    incoming,
    policy
  }) {
    if (!current) {
      return {
        conflict: false,
        reason:
          "no_current_state"
      };
    }

    const same =
      equivalent(
        current.value,
        incoming.value,
        policy.conflictTolerance
      );

    if (same) {
      return {
        conflict: false,
        reason:
          "equivalent_value"
      };
    }

    const bothHighConfidence =
      Number(current.confidence || 0) >=
        policy.minimumConfidence &&
      Number(incoming.confidence || 0) >=
        policy.minimumConfidence;

    return {
      conflict:
        bothHighConfidence,
      reason:
        bothHighConfidence
          ? "high_confidence_value_conflict"
          : "resolvable_value_difference"
    };
  }

  global.INFINICUS.DT
    .stateConflictDetector =
      Object.freeze({
        equivalent,
        detect
      });
})(window);

/* --- INFINICUS-DT-16-Business-State-Synchronization-Engine/src/sync/state-selector.js --- */
(function (global) {
  "use strict";

  function sourceRank(
    sourceType,
    policy
  ) {
    const index =
      policy.sourcePriority
        .indexOf(sourceType);

    return index === -1
      ? Number.MAX_SAFE_INTEGER
      : index;
  }

  function ageMinutes(timestamp) {
    const time =
      new Date(timestamp).getTime();

    return Number.isNaN(time)
      ? Infinity
      : Math.max(
          0,
          (
            Date.now() -
            time
          ) / 60000
        );
  }

  function choose(
    current,
    incoming,
    policy
  ) {
    if (!current) {
      return {
        selected:
          incoming,
        reason:
          "first_value"
      };
    }

    const incomingAge =
      ageMinutes(
        incoming.observedAt
      );

    if (
      incomingAge >
      policy.maximumAgeMinutes
    ) {
      return {
        selected:
          current,
        reason:
          "incoming_stale"
      };
    }

    const currentRank =
      sourceRank(
        current.sourceType,
        policy
      );

    const incomingRank =
      sourceRank(
        incoming.sourceType,
        policy
      );

    if (
      incomingRank <
      currentRank
    ) {
      return {
        selected:
          incoming,
        reason:
          "higher_priority_source"
      };
    }

    if (
      incomingRank >
      currentRank
    ) {
      return {
        selected:
          current,
        reason:
          "lower_priority_source"
      };
    }

    if (
      Number(incoming.confidence || 0) >
      Number(current.confidence || 0)
    ) {
      return {
        selected:
          incoming,
        reason:
          "higher_confidence"
      };
    }

    if (
      new Date(
        incoming.observedAt
      ).getTime() >
      new Date(
        current.observedAt
      ).getTime()
    ) {
      return {
        selected:
          incoming,
        reason:
          "newer_observation"
      };
    }

    return {
      selected:
        current,
      reason:
        "current_retained"
    };
  }

  global.INFINICUS.DT.stateSelector =
    Object.freeze({
      sourceRank,
      ageMinutes,
      choose
    });
})(window);

