/* --- INFINICUS-DT-20-Opportunity-Strategic-Position-Engine/src/analysis/opportunity-scorer.js --- */
(function (global) {
  "use strict";

  function clamp(value) {
    return Math.max(
      0,
      Math.min(
        100,
        Number(value || 0)
      )
    );
  }

  function score(opportunity) {
    const value =
      clamp(
        opportunity.expectedValueScore
      );

    const readiness =
      clamp(opportunity.readinessScore);

    const feasibility =
      clamp(opportunity.feasibilityScore);

    const fit =
      clamp(
        opportunity.strategicFitScore
      );

    const effort =
      clamp(opportunity.effortScore);

    const risk =
      clamp(opportunity.riskScore);

    const grossScore =
      (
        value * 0.30 +
        readiness * 0.20 +
        feasibility * 0.20 +
        fit * 0.20 +
        (100 - effort) * 0.10
      );

    const riskAdjustedScore =
      grossScore *
      (1 - risk / 100);

    return {
      grossOpportunityScore:
        Number(grossScore.toFixed(4)),
      riskAdjustedOpportunityScore:
        Number(
          riskAdjustedScore.toFixed(4)
        )
    };
  }

  function category(scoreValue) {
    if (scoreValue >= 75) return "priority";
    if (scoreValue >= 50) return "promising";
    if (scoreValue >= 30) return "conditional";
    return "low_priority";
  }

  global.INFINICUS.DT.opportunityScorer =
    Object.freeze({
      clamp,
      score,
      category
    });
})(window);

/* --- INFINICUS-DT-20-Opportunity-Strategic-Position-Engine/src/analysis/portfolio-analyzer.js --- */
(function (global) {
  "use strict";

  function analyze(
    opportunities = [],
    capabilities = []
  ) {
    const capabilityById =
      new Map(
        capabilities.map(item => [
          item.strategicCapabilityId,
          item
        ])
      );

    const enriched =
      opportunities.map(opportunity => {
        const scoring =
          global.INFINICUS.DT
            .opportunityScorer
            .score(opportunity);

        const capabilityGaps =
          opportunity.requiredCapabilityIds
            .map(id =>
              capabilityById.get(id)
            )
            .filter(Boolean)
            .filter(capability =>
              capability.currentStrengthScore <
              capability.targetStrengthScore
            )
            .map(capability => ({
              strategicCapabilityId:
                capability
                  .strategicCapabilityId,
              name:
                capability.name,
              gap:
                Number(
                  (
                    capability
                      .targetStrengthScore -
                    capability
                      .currentStrengthScore
                  ).toFixed(4)
                )
            }));

        return {
          ...structuredClone(opportunity),
          ...scoring,
          priorityCategory:
            global.INFINICUS.DT
              .opportunityScorer
              .category(
                scoring
                  .riskAdjustedOpportunityScore
              ),
          capabilityGaps
        };
      });

    const ranked =
      [...enriched].sort(
        (a, b) =>
          b.riskAdjustedOpportunityScore -
          a.riskAdjustedOpportunityScore
      );

    const byDomain = new Map();

    for (const item of enriched) {
      if (!byDomain.has(item.domain)) {
        byDomain.set(item.domain, []);
      }

      byDomain.get(item.domain)
        .push(item);
    }

    const domains =
      [...byDomain.entries()]
        .map(([domain, items]) => ({
          domain,
          opportunityCount:
            items.length,
          averageRiskAdjustedScore:
            Number(
              (
                items.reduce(
                  (sum, item) =>
                    sum +
                    item
                      .riskAdjustedOpportunityScore,
                  0
                ) / items.length
              ).toFixed(4)
            )
        }))
        .sort(
          (a, b) =>
            b.averageRiskAdjustedScore -
            a.averageRiskAdjustedScore
        );

    return {
      enriched,
      ranked,
      domains,
      priorityCount:
        enriched.filter(
          item =>
            item.priorityCategory ===
            "priority"
        ).length,
      averageRiskAdjustedScore:
        enriched.length
          ? Number(
              (
                enriched.reduce(
                  (sum, item) =>
                    sum +
                    item
                      .riskAdjustedOpportunityScore,
                  0
                ) / enriched.length
              ).toFixed(4)
            )
          : 0
    };
  }

  global.INFINICUS.DT
    .opportunityPortfolioAnalyzer =
      Object.freeze({ analyze });
})(window);

/* --- INFINICUS-DT-20-Opportunity-Strategic-Position-Engine/src/validation/opportunity-validator.js --- */
(function (global) {
  "use strict";

  function validate({
    opportunities = [],
    capabilities = [],
    synchronizedState = []
  } = {}) {
    const issues = [];

    const capabilityIds =
      new Set(
        capabilities.map(
          item =>
            item.strategicCapabilityId
        )
      );

    const stateKeys =
      new Set(
        synchronizedState.map(
          item =>
            item.stateKey
        )
      );

    for (
      const opportunity
      of opportunities
    ) {
      for (
        const capabilityId
        of opportunity
          .requiredCapabilityIds
      ) {
        if (
          !capabilityIds.has(
            capabilityId
          )
        ) {
          issues.push(
            `Unknown required capability: ${capabilityId}`
          );
        }
      }

      for (
        const stateKey
        of opportunity
          .dependencyStateKeys
      ) {
        if (!stateKeys.has(stateKey)) {
          issues.push(
            `Unknown opportunity dependency state: ${stateKey}`
          );
        }
      }

      for (const field of [
        "expectedValueScore",
        "readinessScore",
        "feasibilityScore",
        "strategicFitScore",
        "effortScore",
        "riskScore"
      ]) {
        if (
          opportunity[field] < 0 ||
          opportunity[field] > 100
        ) {
          issues.push(
            `${field} must be between 0 and 100.`
          );
        }
      }

      if (
        opportunity.confidence < 0 ||
        opportunity.confidence > 1
      ) {
        issues.push(
          "Opportunity confidence must be between 0 and 1."
        );
      }
    }

    return {
      valid:
        issues.length === 0,
      issues
    };
  }

  global.INFINICUS.DT
    .opportunityValidator =
      Object.freeze({ validate });
})(window);

/* --- INFINICUS-DT-20-Opportunity-Strategic-Position-Engine/src/storage/opportunity-store.js --- */
(function (global) {
  "use strict";

  const runtime =
    global.INFINICUS.DT.runtime;

  const DB_NAME =
    "INFINICUS_DT_OPPORTUNITY_STRATEGY";

  let dbPromise;

  const request = req =>
    new Promise((resolve, reject) => {
      req.onsuccess = () =>
        resolve(req.result);
      req.onerror = () =>
        reject(req.error);
    });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise =
      new Promise((resolve, reject) => {
        const req =
          indexedDB.open(DB_NAME, 1);

        req.onupgradeneeded = () => {
          const db = req.result;

          for (const [name, keyPath] of [
            ["capabilities", "strategicCapabilityId"],
            ["opportunities", "strategicOpportunityId"],
            ["snapshots", "strategicPositionSnapshotId"],
            ["integrity_handoffs", "integrityHandoffId"]
          ]) {
            if (
              !db.objectStoreNames
                .contains(name)
            ) {
              const store =
                db.createObjectStore(
                  name,
                  { keyPath }
                );

              if (
                [
                  "capabilities",
                  "opportunities"
                ].includes(name)
              ) {
                store.createIndex(
                  "twinId",
                  "twinId",
                  { unique: false }
                );
              }
            }
          }
        };

        req.onsuccess = () =>
          resolve(req.result);

        req.onerror = () =>
          reject(req.error);
      });

    return dbPromise;
  }

  async function put(
    storeName,
    record
  ) {
    try {
      const db = await open();

      const tx =
        db.transaction(
          storeName,
          "readwrite"
        );

      await request(
        tx.objectStore(storeName)
          .put(structuredClone(record))
      );

      return runtime.success(
        structuredClone(record)
      );
    } catch (error) {
      return runtime.failure(
        "OPPORTUNITY_STORAGE_ERROR",
        error?.message ||
          "Opportunity storage failed."
      );
    }
  }

  async function get(
    storeName,
    id
  ) {
    try {
      const db = await open();

      const tx =
        db.transaction(
          storeName,
          "readonly"
        );

      const value =
        await request(
          tx.objectStore(storeName)
            .get(id)
        );

      return value
        ? runtime.success(
            structuredClone(value)
          )
        : runtime.failure(
            "OPPORTUNITY_RECORD_NOT_FOUND",
            "Opportunity record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "OPPORTUNITY_STORAGE_ERROR",
        error?.message ||
          "Opportunity retrieval failed."
      );
    }
  }

  async function listByTwin(
    storeName,
    twinId
  ) {
    try {
      const db = await open();

      const tx =
        db.transaction(
          storeName,
          "readonly"
        );

      const values =
        await request(
          tx.objectStore(storeName)
            .index("twinId")
            .getAll(twinId)
        );

      return runtime.success(
        values.map(structuredClone)
      );
    } catch (error) {
      return runtime.failure(
        "OPPORTUNITY_STORAGE_ERROR",
        error?.message ||
          "Opportunity listing failed."
      );
    }
  }

  global.INFINICUS.DT.opportunityStore =
    Object.freeze({
      open,
      put,
      get,
      listByTwin
    });
})(window);

/* --- INFINICUS-DT-20-Opportunity-Strategic-Position-Engine/src/engine/opportunity-strategic-position-engine.js --- */
(function (global) {
  "use strict";

  const runtime =
    global.INFINICUS.DT.runtime;

  async function buildStrategicPosition({
    opportunityHandoffId,
    capabilityInputs = [],
    opportunityInputs = []
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .riskVulnerabilityStateEngine
        .getOpportunityHandoff({
          opportunityHandoffId
        });

    if (!handoff.ok) return handoff;

    const capabilities = [];

    for (
      const input
      of capabilityInputs
    ) {
      const built =
        global.INFINICUS.DT
          .strategicCapabilityModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId
          });

      if (!built.ok) return built;

      capabilities.push(
        built.data
      );

      await global.INFINICUS.DT
        .opportunityStore
        .put(
          "capabilities",
          built.data
        );
    }

    const opportunities = [];

    for (
      const input
      of opportunityInputs
    ) {
      const built =
        global.INFINICUS.DT
          .strategicOpportunityModel
          .create({
            ...input,
            twinId:
              handoff.data.twinId,
            businessId:
              handoff.data.businessId
          });

      if (!built.ok) return built;

      opportunities.push(
        built.data
      );
    }

    const validation =
      global.INFINICUS.DT
        .opportunityValidator
        .validate({
          opportunities,
          capabilities,
          synchronizedState:
            handoff.data.synchronizedState
        });

    if (!validation.valid) {
      return runtime.failure(
        "OPPORTUNITY_STRATEGIC_STATE_INVALID",
        "Opportunity and strategic-position validation failed.",
        validation
      );
    }

    for (
      const opportunity
      of opportunities
    ) {
      await global.INFINICUS.DT
        .opportunityStore
        .put(
          "opportunities",
          opportunity
        );
    }

    const analysis =
      global.INFINICUS.DT
        .opportunityPortfolioAnalyzer
        .analyze(
          opportunities,
          capabilities
        );

    const snapshot = {
      strategicPositionSnapshotId:
        runtime.createId(
          "dt_strategic_position_snapshot"
        ),
      opportunityHandoffId,
      riskSnapshotId:
        handoff.data.riskSnapshotId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      capabilities:
        capabilities.map(
          runtime.clone
        ),
      opportunities:
        opportunities.map(
          runtime.clone
        ),
      analysis:
        runtime.clone(analysis),
      riskAnalysis:
        runtime.clone(
          handoff.data.riskAnalysis
        ),
      status:
        analysis.priorityCount > 0
          ? "opportunity_ready"
          : "current",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .opportunityStore
      .put("snapshots", snapshot);

    const integrityHandoff = {
      integrityHandoffId:
        runtime.createId(
          "dt_integrity_handoff"
        ),
      targetBlock: "DT-21",
      strategicPositionSnapshotId:
        snapshot
          .strategicPositionSnapshotId,
      riskSnapshotId:
        handoff.data.riskSnapshotId,
      businessId:
        snapshot.businessId,
      twinId:
        snapshot.twinId,
      strategicCapabilities:
        capabilities.map(
          runtime.clone
        ),
      opportunities:
        analysis.enriched.map(
          runtime.clone
        ),
      opportunityAnalysis:
        runtime.clone(analysis),
      riskAnalysis:
        runtime.clone(
          handoff.data.riskAnalysis
        ),
      vulnerabilities:
        handoff.data.vulnerabilities
          .map(runtime.clone),
      synchronizedState:
        handoff.data.synchronizedState
          .map(runtime.clone),
      businessEvents:
        handoff.data.businessEvents
          .map(runtime.clone),
      breaches:
        handoff.data.breaches
          .map(runtime.clone),
      correlationId:
        handoff.data.correlationId,
      status: "ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .opportunityStore
      .put(
        "integrity_handoffs",
        integrityHandoff
      );

    await runtime.emit(
      "dt.strategic_position.completed",
      {
        strategicPositionSnapshot:
          snapshot,
        integrityHandoffId:
          integrityHandoff
            .integrityHandoffId
      }
    );

    return runtime.success({
      strategicPositionSnapshot:
        snapshot,
      integrityHandoff
    });
  }

  const api = Object.freeze({
    buildStrategicPosition,
    getStrategicPositionSnapshot: ({
      strategicPositionSnapshotId
    }) =>
      global.INFINICUS.DT
        .opportunityStore
        .get(
          "snapshots",
          strategicPositionSnapshotId
        ),
    getIntegrityHandoff: ({
      integrityHandoffId
    }) =>
      global.INFINICUS.DT
        .opportunityStore
        .get(
          "integrity_handoffs",
          integrityHandoffId
        ),
    listTwinCapabilities: ({
      twinId
    }) =>
      global.INFINICUS.DT
        .opportunityStore
        .listByTwin(
          "capabilities",
          twinId
        ),
    listTwinOpportunities: ({
      twinId
    }) =>
      global.INFINICUS.DT
        .opportunityStore
        .listByTwin(
          "opportunities",
          twinId
        )
  });

  runtime.registerService(
    "dt.opportunity_strategic_position",
    api,
    { block: "DT-20" }
  );

  runtime.registerRoute(
    "dt.strategic_position.build",
    buildStrategicPosition
  );

  global.INFINICUS.DT
    .opportunityStrategicPositionEngine =
      api;
})(window);

