/* --- INFINICUS-DT-21-Twin-Integrity-Consistency-Confidence-Engine/src/model/integrity-policy.js --- */
(function (global) {
  "use strict";

  function create(input = {}) {
    const runtime = global.INFINICUS.DT.runtime;

    return runtime.success({
      integrityPolicyId:
        input.integrityPolicyId ||
        runtime.createId("dt_integrity_policy"),
      name:
        String(input.name || "Default twin integrity policy"),
      requiredDomains:
        Array.isArray(input.requiredDomains)
          ? input.requiredDomains.map(String)
          : [
              "financial",
              "customer",
              "sales",
              "marketing",
              "operations",
              "inventory",
              "workforce",
              "asset",
              "market",
              "risk",
              "opportunity"
            ],
      minimumOverallConfidence:
        Math.max(0, Math.min(1, Number(input.minimumOverallConfidence ?? 0.65))),
      maximumStateAgeMinutes:
        Math.max(1, Number(input.maximumStateAgeMinutes || 1440)),
      maximumConflictCount:
        Math.max(0, Number(input.maximumConflictCount || 0)),
      maximumBlockingBreachCount:
        Math.max(0, Number(input.maximumBlockingBreachCount || 0)),
      maximumAssumedStatePercent:
        Math.max(0, Math.min(100, Number(input.maximumAssumedStatePercent ?? 20))),
      minimumReadinessScore:
        Math.max(0, Math.min(100, Number(input.minimumReadinessScore ?? 70))),
      status:
        String(input.status || "active"),
      createdAt:
        new Date().toISOString()
    });
  }

  global.INFINICUS.DT.integrityPolicyModel =
    Object.freeze({ create });
})(window);

/* --- INFINICUS-DT-21-Twin-Integrity-Consistency-Confidence-Engine/src/validation/integrity-validator.js --- */
(function (global) {
  "use strict";

  function domainFromKey(stateKey) {
    return String(stateKey || "").split(".")[0] || "unknown";
  }

  function validate({
    handoff,
    policy
  }) {
    const issues = [];
    const states = handoff.synchronizedState || [];
    const domains = new Set(states.map(item => domainFromKey(item.stateKey)));

    for (const domain of policy.requiredDomains) {
      if (!domains.has(domain)) {
        issues.push({
          code: "REQUIRED_DOMAIN_MISSING",
          severity: "high",
          domain,
          message: `Required twin domain is missing: ${domain}`
        });
      }
    }

    const invalidConfidence = states.filter(item =>
      Number(item.confidence) < 0 ||
      Number(item.confidence) > 1
    );

    if (invalidConfidence.length) {
      issues.push({
        code: "INVALID_CONFIDENCE",
        severity: "high",
        count: invalidConfidence.length,
        message: "One or more states have invalid confidence values."
      });
    }

    const simulated = states.filter(item =>
      item.sourceType === "simulated"
    );

    if (simulated.length) {
      issues.push({
        code: "SIMULATED_STATE_IN_ACTUAL_TWIN",
        severity: "critical",
        count: simulated.length,
        message: "Simulated state is present in the actual synchronized twin."
      });
    }

    const assumed = states.filter(item =>
      item.sourceType === "assumed"
    );

    const assumedPercent =
      states.length === 0
        ? 0
        : assumed.length / states.length * 100;

    if (assumedPercent > policy.maximumAssumedStatePercent) {
      issues.push({
        code: "ASSUMED_STATE_EXCESSIVE",
        severity: "medium",
        assumedPercent: Number(assumedPercent.toFixed(4)),
        message: "Assumed-state percentage exceeds policy."
      });
    }

    const stale = states.filter(item => {
      const timestamp = new Date(
        item.observedAt || item.updatedAt || item.createdAt
      ).getTime();

      if (Number.isNaN(timestamp)) return true;

      return (
        Date.now() - timestamp
      ) / 60000 > policy.maximumStateAgeMinutes;
    });

    if (stale.length) {
      issues.push({
        code: "STALE_STATE_PRESENT",
        severity: "medium",
        count: stale.length,
        message: "One or more synchronized states exceed freshness policy."
      });
    }

    const conflicts = handoff.conflicts || [];
    const blockingBreaches = (handoff.breaches || [])
      .filter(item => item.status === "blocking");

    if (conflicts.length > policy.maximumConflictCount) {
      issues.push({
        code: "UNRESOLVED_CONFLICTS",
        severity: "high",
        count: conflicts.length,
        message: "Unresolved state conflicts exceed policy."
      });
    }

    if (blockingBreaches.length > policy.maximumBlockingBreachCount) {
      issues.push({
        code: "BLOCKING_BREACHES",
        severity: "critical",
        count: blockingBreaches.length,
        message: "Blocking constraint breaches exceed policy."
      });
    }

    return {
      valid: !issues.some(issue =>
        ["high", "critical"].includes(issue.severity)
      ),
      issues,
      domainCount: domains.size,
      stateCount: states.length,
      assumedPercent: Number(assumedPercent.toFixed(4)),
      staleStateCount: stale.length,
      conflictCount: conflicts.length,
      blockingBreachCount: blockingBreaches.length
    };
  }

  global.INFINICUS.DT.twinIntegrityValidator =
    Object.freeze({ domainFromKey, validate });
})(window);

/* --- INFINICUS-DT-21-Twin-Integrity-Consistency-Confidence-Engine/src/analysis/confidence-readiness.js --- */
(function (global) {
  "use strict";

  function weightedConfidence(states = []) {
    if (!states.length) return 0;

    const weights = {
      observed: 1,
      calculated: 0.9,
      inferred: 0.7,
      assumed: 0.4,
      simulated: 0
    };

    const weighted = states.reduce((sum, state) => {
      const sourceWeight = weights[state.sourceType] ?? 0.5;
      return sum + Number(state.confidence || 0) * sourceWeight;
    }, 0);

    return Number((weighted / states.length).toFixed(4));
  }

  function score({
    validation,
    confidence,
    opportunityAnalysis,
    riskAnalysis,
    policy
  }) {
    let readiness = 100;

    readiness -= Math.min(30, validation.issues.length * 4);
    readiness -= Math.min(25, validation.staleStateCount * 0.5);
    readiness -= Math.min(25, validation.conflictCount * 5);
    readiness -= Math.min(30, validation.blockingBreachCount * 10);
    readiness -= Math.max(0, validation.assumedPercent - policy.maximumAssumedStatePercent);
    readiness -= Math.max(
      0,
      (policy.minimumOverallConfidence - confidence) * 100
    );

    const riskPenalty =
      Math.min(20, Number(riskAnalysis?.maximumResidualRiskScore || 0) * 0.2);

    readiness -= riskPenalty;

    const opportunityBonus =
      Math.min(
        5,
        Number(opportunityAnalysis?.priorityCount || 0)
      );

    readiness += opportunityBonus;

    readiness = Math.max(0, Math.min(100, readiness));

    return {
      readinessScore: Number(readiness.toFixed(4)),
      overallConfidence: confidence,
      ready:
        readiness >= policy.minimumReadinessScore &&
        confidence >= policy.minimumOverallConfidence &&
        validation.valid,
      riskPenalty: Number(riskPenalty.toFixed(4)),
      opportunityBonus
    };
  }

  global.INFINICUS.DT.confidenceReadinessAnalyzer =
    Object.freeze({ weightedConfidence, score });
})(window);

/* --- INFINICUS-DT-21-Twin-Integrity-Consistency-Confidence-Engine/src/storage/integrity-store.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;
  const DB_NAME = "INFINICUS_DT_INTEGRITY_CONFIDENCE";
  let dbPromise;

  const request = req => new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  function open() {
    if (dbPromise) return dbPromise;

    dbPromise = new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);

      req.onupgradeneeded = () => {
        const db = req.result;

        for (const [name, keyPath] of [
          ["policies", "integrityPolicyId"],
          ["issues", "integrityIssueId"],
          ["snapshots", "integritySnapshotId"],
          ["history_handoffs", "historyHandoffId"]
        ]) {
          if (!db.objectStoreNames.contains(name)) {
            db.createObjectStore(name, { keyPath });
          }
        }
      };

      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });

    return dbPromise;
  }

  async function put(storeName, record) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readwrite");
      await request(tx.objectStore(storeName).put(structuredClone(record)));
      return runtime.success(structuredClone(record));
    } catch (error) {
      return runtime.failure(
        "INTEGRITY_STORAGE_ERROR",
        error?.message || "Integrity storage failed."
      );
    }
  }

  async function get(storeName, id) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const value = await request(tx.objectStore(storeName).get(id));

      return value
        ? runtime.success(structuredClone(value))
        : runtime.failure(
            "INTEGRITY_RECORD_NOT_FOUND",
            "Integrity record was not found.",
            { storeName, id }
          );
    } catch (error) {
      return runtime.failure(
        "INTEGRITY_STORAGE_ERROR",
        error?.message || "Integrity retrieval failed."
      );
    }
  }

  async function list(storeName) {
    try {
      const db = await open();
      const tx = db.transaction(storeName, "readonly");
      const values = await request(tx.objectStore(storeName).getAll());

      return runtime.success(values.map(structuredClone));
    } catch (error) {
      return runtime.failure(
        "INTEGRITY_STORAGE_ERROR",
        error?.message || "Integrity listing failed."
      );
    }
  }

  global.INFINICUS.DT.integrityStore =
    Object.freeze({ open, put, get, list });
})(window);

/* --- INFINICUS-DT-21-Twin-Integrity-Consistency-Confidence-Engine/src/engine/twin-integrity-confidence-engine.js --- */
(function (global) {
  "use strict";

  const runtime = global.INFINICUS.DT.runtime;

  async function registerPolicy(input = {}) {
    const built =
      global.INFINICUS.DT
        .integrityPolicyModel
        .create(input);

    if (!built.ok) return built;

    return global.INFINICUS.DT
      .integrityStore
      .put("policies", built.data);
  }

  async function validateTwin({
    integrityHandoffId,
    integrityPolicyId
  } = {}) {
    const handoff =
      await global.INFINICUS.DT
        .opportunityStrategicPositionEngine
        .getIntegrityHandoff({
          integrityHandoffId
        });

    if (!handoff.ok) return handoff;

    const policy =
      await global.INFINICUS.DT
        .integrityStore
        .get("policies", integrityPolicyId);

    if (!policy.ok) return policy;

    const validation =
      global.INFINICUS.DT
        .twinIntegrityValidator
        .validate({
          handoff: handoff.data,
          policy: policy.data
        });

    const confidence =
      global.INFINICUS.DT
        .confidenceReadinessAnalyzer
        .weightedConfidence(
          handoff.data.synchronizedState
        );

    const readiness =
      global.INFINICUS.DT
        .confidenceReadinessAnalyzer
        .score({
          validation,
          confidence,
          opportunityAnalysis:
            handoff.data.opportunityAnalysis,
          riskAnalysis:
            handoff.data.riskAnalysis,
          policy:
            policy.data
        });

    const issueRecords = [];

    for (const issue of validation.issues) {
      const record = {
        integrityIssueId:
          runtime.createId("dt_integrity_issue"),
        integrityHandoffId,
        businessId:
          handoff.data.businessId,
        twinId:
          handoff.data.twinId,
        ...runtime.clone(issue),
        status: "open",
        correlationId:
          handoff.data.correlationId,
        createdAt:
          new Date().toISOString()
      };

      issueRecords.push(record);

      await global.INFINICUS.DT
        .integrityStore
        .put("issues", record);
    }

    const snapshot = {
      integritySnapshotId:
        runtime.createId("dt_integrity_snapshot"),
      integrityHandoffId,
      integrityPolicyId,
      strategicPositionSnapshotId:
        handoff.data.strategicPositionSnapshotId,
      riskSnapshotId:
        handoff.data.riskSnapshotId,
      businessId:
        handoff.data.businessId,
      twinId:
        handoff.data.twinId,
      validation:
        runtime.clone(validation),
      readiness:
        runtime.clone(readiness),
      issues:
        issueRecords.map(runtime.clone),
      opportunityAnalysis:
        runtime.clone(handoff.data.opportunityAnalysis),
      riskAnalysis:
        runtime.clone(handoff.data.riskAnalysis),
      stateCount:
        handoff.data.synchronizedState.length,
      status:
        readiness.ready
          ? "validated"
          : "not_ready",
      correlationId:
        handoff.data.correlationId,
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .integrityStore
      .put("snapshots", snapshot);

    const historyHandoff = {
      historyHandoffId:
        runtime.createId("dt_history_handoff"),
      targetBlock: "DT-22",
      integritySnapshotId:
        snapshot.integritySnapshotId,
      strategicPositionSnapshotId:
        handoff.data.strategicPositionSnapshotId,
      riskSnapshotId:
        handoff.data.riskSnapshotId,
      businessId:
        snapshot.businessId,
      twinId:
        snapshot.twinId,
      synchronizedState:
        handoff.data.synchronizedState.map(runtime.clone),
      businessEvents:
        handoff.data.businessEvents.map(runtime.clone),
      opportunities:
        handoff.data.opportunities.map(runtime.clone),
      vulnerabilities:
        handoff.data.vulnerabilities.map(runtime.clone),
      breaches:
        handoff.data.breaches.map(runtime.clone),
      integrityValidation:
        runtime.clone(validation),
      readiness:
        runtime.clone(readiness),
      correlationId:
        handoff.data.correlationId,
      status:
        readiness.ready
          ? "ready"
          : "not_ready",
      createdAt:
        new Date().toISOString()
    };

    await global.INFINICUS.DT
      .integrityStore
      .put("history_handoffs", historyHandoff);

    await runtime.emit(
      "dt.twin_integrity.validated",
      {
        integritySnapshot: snapshot,
        historyHandoffId:
          historyHandoff.historyHandoffId
      }
    );

    return runtime.success({
      integritySnapshot: snapshot,
      historyHandoff
    });
  }

  const api = Object.freeze({
    registerPolicy,
    validateTwin,
    getIntegritySnapshot: ({ integritySnapshotId }) =>
      global.INFINICUS.DT
        .integrityStore
        .get("snapshots", integritySnapshotId),
    getHistoryHandoff: ({ historyHandoffId }) =>
      global.INFINICUS.DT
        .integrityStore
        .get("history_handoffs", historyHandoffId),
    listIntegrityIssues: () =>
      global.INFINICUS.DT
        .integrityStore
        .list("issues")
  });

  runtime.registerService(
    "dt.twin_integrity_confidence",
    api,
    { block: "DT-21" }
  );

  runtime.registerRoute(
    "dt.integrity_policy.register",
    registerPolicy
  );

  runtime.registerRoute(
    "dt.twin_integrity.validate",
    validateTwin
  );

  global.INFINICUS.DT
    .twinIntegrityConfidenceEngine = api;
})(window);

